-- Schema for Domain: merchandising | Business: Apparel Fashion | Version: v1_mvm
-- Generated on: 2026-05-05 18:07:22

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `apparel_fashion_ecm`.`merchandising` COMMENT 'Drives assortment planning, collection planning, OTB budgets, allocation strategies, pricing (MSRP, AUR, IMU, MMU, MU, MD), and GMROI optimization. Manages seasonal buy plans, pre-production planning, sell-through rate (STR) analysis, and merchandise financial planning via Oracle Retail Merchandising System and Anaplan.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`assortment_plan` (
    `assortment_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the assortment plan record in the Databricks Silver Layer. Primary key generated by the lakehouse ingestion pipeline from Oracle Retail Merchandising System assortment planning module.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Assortment plans are sized to support seasonal marketing campaigns. Merchandisers need campaign timing, expected lift, and channel mix to plan OTB budgets and style counts. This link enables campaign-',
    `cluster_id` BIGINT COMMENT 'Reference to the store cluster grouping used for assortment localization. Store clusters segment stores by volume tier, climate zone, or customer demographics to enable differentiated assortment depth and size curve optimization within Oracle Retail allocation module.',
    `collection_id` BIGINT COMMENT 'Reference to the parent collection or line plan in Centric PLM or Oracle Retail. Links the assortment plan to the upstream collection planning and product design lifecycle managed in Centric PLM collection management module.',
    `collection_plan_id` BIGINT COMMENT 'Foreign key linking to merchandising.collection_plan. Business justification: Assortment plans operationalize collection plans by defining the specific SKU-level assortments, store clusters, and channel strategies for a collection. The collection_plan defines the thematic visio',
    `colorway_id` BIGINT COMMENT 'Foreign key linking to product.colorway. Business justification: Assortment plans track colorway_count_planned and drive color depth decisions per season. Planners select specific colorways for inclusion in an assortment. This FK enables colorway-level assortment a',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Assortment plans are budgeted and tracked against cost centers for departmental P&L accountability. Merchandising teams must report plan performance (sales, margin, markdown) by cost center for financ',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Assortment plans target specific customer segments (Gen Z urban, affluent suburban, value-conscious families). Segment demographics and preferences drive category mix, price points, and style selectio',
    `distribution_center_id` BIGINT COMMENT 'Foreign key linking to logistics.distribution_center. Business justification: Receipt planning and DC allocation strategy: assortment plans must identify the receiving DC to enable inbound capacity planning and channel allocation. Apparel planners assign assortments to DCs to c',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Assortment plans contain markdown_budget_amount and IMU/MMU targets that map to GL accounts for markdown expense and inventory valuation. Finance uses GL account assignment on assortment plans for mar',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Assortment plans have department_id, class_id, subclass_id but no FK to merchandise_hierarchy master. Adding merchandise_hierarchy_id FK normalizes merchandise classification and removes redundant hie',
    `otb_budget_id` BIGINT COMMENT 'Foreign key linking to merchandising.otb_budget. Business justification: Assortment plans reference OTB budget amounts but have no FK to otb_budget master. Adding otb_budget_id FK normalizes budget reference and removes redundant otb_budget_amount. FK will reference mercha',
    `production_factory_id` BIGINT COMMENT 'Foreign key linking to production.factory. Business justification: Strategic assortment plans designate preferred factories based on capability, capacity, and cost structure. Drives sourcing strategy and factory capacity reservation for seasonal collections.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Assortment plans drive revenue and margin by channel/brand, tracked via profit centers. Financial reporting requires linking planned vs actual performance (sales, GMROI, STR) to profit centers for seg',
    `rfq_id` BIGINT COMMENT 'Foreign key linking to sourcing.rfq. Business justification: Assortment planning directly triggers RFQ issuance in apparel sourcing. Merchandisers finalize the assortment plan and sourcing issues RFQs against it. This link enables assortment-to-sourcing traceab',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Assortment plans are inherently seasonal; season_code exists but no FK to season master. Adding season_id FK normalizes season reference and removes redundant season_code. FK will reference merchandis',
    `style_id` BIGINT COMMENT 'Foreign key linking to product.style. Business justification: Assortment planning is the core merchandising process of selecting which styles enter a seasons range. Planners build style-level assortment decisions (range reviews, OTB by style, style count target',
    `tna_calendar_id` BIGINT COMMENT 'Foreign key linking to sourcing.sourcing_tna_calendar. Business justification: Assortment plans drive TNA calendar creation — the TNA calendar tracks all milestones required to deliver the assortment on time. Buyers and planners monitor TNA calendars against assortment plan floo',
    `vendor_cost_quote_id` BIGINT COMMENT 'Foreign key linking to sourcing.vendor_cost_quote. Business justification: Assortment planners validate IMU targets against vendor cost quotes during plan finalization. The assortment plans imu_target_pct and aur_target are directly validated against vendor_cost_quote.fob_c',
    `allocation_strategy` STRING COMMENT 'Inventory allocation methodology applied to this assortment plan. top_down = corporate-driven allocation to stores; bottom_up = store-requested replenishment; hybrid = combination approach; vmi = Vendor Managed Inventory (VMI) where the supplier manages replenishment. Drives Oracle Retail allocation module configuration.. Valid values are `top_down|bottom_up|hybrid|vmi`',
    `approval_date` DATE COMMENT 'Date on which the assortment plan was formally approved and the OTB budget was committed. Marks the transition from submitted to approved status and triggers downstream PO generation and T&A calendar activation in SAP S/4HANA and Infor PLM.',
    `aur_target` DECIMAL(18,2) COMMENT 'Planned Average Unit Retail (AUR) price for the assortment, representing the expected average selling price per unit across all styles and colorways in the plan. A key KPI in Anaplan merchandise financial planning used to project net sales and validate GMROI targets.',
    `carry_forward_pct` DECIMAL(18,2) COMMENT 'Percentage of styles in this assortment plan that are carried forward from the prior season versus new introductions. A key collection planning metric used by merchants to balance newness investment against proven performers. Expressed as a percentage of total style count.',
    `channel_type` STRING COMMENT 'Distribution channel for which this assortment plan is defined. Drives channel-specific assortment depth, pricing strategy, and OTB budget allocation. DTC (Direct-to-Consumer) includes both retail stores and e-commerce. Values: retail (brick-and-mortar stores), ecommerce (Salesforce Commerce Cloud digital storefront), wholesale (partner accounts), dtc (combined direct channels), outlet (off-price stores).. Valid values are `retail|ecommerce|wholesale|dtc|outlet`',
    `colorway_count_planned` STRING COMMENT 'Number of distinct colorways planned across all styles in the assortment. Colorway depth is a key assortment decision in apparel fashion, balancing color story cohesion against inventory fragmentation risk.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the assortment plan record was first created in the Oracle Retail Merchandising System and ingested into the Databricks Silver Layer. Serves as the RECORD_AUDIT_CREATED for this entity. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary values in this assortment plan (e.g., USD, EUR, GBP). Ensures consistent financial reporting across multi-currency wholesale and DTC channels in SAP S/4HANA FI/CO and Anaplan.. Valid values are `^[A-Z]{3}$`',
    `imu_target_pct` DECIMAL(18,2) COMMENT 'Target Initial Markup (IMU) percentage for the assortment plan, expressed as a percentage of retail price. IMU = (Retail Price − Cost) / Retail Price × 100. Drives cost negotiation targets with suppliers and is a primary input to GMROI optimization in Anaplan merchandise financial planning.',
    `is_final_version` BOOLEAN COMMENT 'Indicates whether this record represents the final approved version of the assortment plan (True) or a superseded draft/revision (False). Used to filter active plan versions in reporting and analytics without requiring version_number logic.',
    `labor_compliance_required` BOOLEAN COMMENT 'Indicates whether suppliers fulfilling this assortment plan must hold active FLA (Fair Labor Association) or WRAP (Worldwide Responsible Accredited Production) certification. Enforced during supplier onboarding in Infor PLM sourcing and SAP S/4HANA MM vendor master.',
    `markdown_budget_amount` DECIMAL(18,2) COMMENT 'Total markdown (MD) budget allocated to this assortment plan for planned price reductions during the selling season. Markdown budget is a key input to MMU calculation and is managed in Anaplan merchandise financial planning and Oracle Retail Price Management.',
    `mmu_target_pct` DECIMAL(18,2) COMMENT 'Target Maintained Markup (MMU) percentage after accounting for planned markdowns (MD), shrinkage, and employee discounts. MMU reflects the realized margin and is the primary profitability metric tracked in Anaplan merchandise financial planning alongside GMROI.',
    `msrp_max` DECIMAL(18,2) COMMENT 'Highest Manufacturers Suggested Retail Price (MSRP) point within the assortment plans price architecture. Defines the ceiling price tier and is used alongside msrp_min to establish the price range strategy and IMU targets for the planned assortment.',
    `msrp_min` DECIMAL(18,2) COMMENT 'Lowest Manufacturers Suggested Retail Price (MSRP) point within the assortment plans price architecture. Defines the entry price tier for the planned assortment and is used in IMU (Initial Markup) and AUR (Average Unit Retail) calculations in Oracle Retail Price Management.',
    `otb_units_planned` STRING COMMENT 'Total number of units planned for procurement under this assortment plans OTB budget. Used to calculate average unit cost, validate MOQ (Minimum Order Quantity) compliance with suppliers, and drive purchase order (PO) generation in SAP S/4HANA MM.',
    `plan_code` STRING COMMENT 'Externally-known business identifier for the assortment plan, assigned by the Oracle Retail Merchandising System. Used by merchants and planners to reference the plan across systems (e.g., ORM-AP-2025-FALL-WMN-001). Serves as the BUSINESS_IDENTIFIER for this entity.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `plan_end_date` DATE COMMENT 'Date on which the assortment plan expires or the season closes. Marks the end of the active selling window and triggers end-of-season markdown (MD) and clearance processes. Serves as the EFFECTIVE_UNTIL for this entity. Nullable for open-ended NOS assortments.',
    `plan_name` STRING COMMENT 'Human-readable name of the assortment plan (e.g., Fall 2025 Womens Outerwear – North America DTC). Used by merchants and planners to identify the plan in reporting dashboards and Anaplan merchandise financial planning views. Serves as the IDENTITY_LABEL for this entity.',
    `plan_start_date` DATE COMMENT 'Date on which the assortment plan becomes effective for in-season execution — i.e., the first floor-set or go-live date for the planned assortment. Used to align T&A (Time and Action) calendar milestones and pre-production (PP) sample review schedules. Serves as the EFFECTIVE_FROM for this MASTER_AGREEMENT-role entity.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the assortment plan within the Oracle Retail Merchandising System workflow. Drives downstream OTB budget release, allocation activation, and collection planning milestones. Valid states: draft (initial creation), submitted (pending merchant approval), approved (OTB committed), active (in-season execution), closed (season ended), cancelled (plan voided). Serves as the LIFECYCLE_STATUS for this entity.. Valid values are `draft|submitted|approved|active|closed|cancelled`',
    `plan_type` STRING COMMENT 'Classification of the assortment plan by merchandise strategy. seasonal = time-bound seasonal collection; core = evergreen carry-forward styles; nos = Never Out of Stock (NOS) replenishment assortment; capsule = limited-edition capsule collection; collab = brand collaboration or licensed assortment. Drives OTB budget methodology and replenishment logic.. Valid values are `seasonal|core|nos|capsule|collab`',
    `replenishment_eligible` BOOLEAN COMMENT 'Indicates whether styles within this assortment plan are eligible for automated replenishment (True) or are one-time buys with no replenishment (False). NOS (Never Out of Stock) assortments are always True. Drives replenishment trigger logic in Oracle Retail allocation and Manhattan Associates WMS.',
    `season_year` STRING COMMENT 'Four-digit calendar year associated with the merchandise season (e.g., 2025). Used for year-over-year sell-through rate (STR) comparisons and GMROI trend analysis in Anaplan financial planning.',
    `size_range` STRING COMMENT 'Planned size range for the assortment (e.g., XS-3XL, 00-24, 5-13). Defines the inclusive size offering for the plan and is used to validate size curve alignment with store cluster demographics and FTC textile labeling requirements.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this assortment plan record originated. ORM = Oracle Retail Merchandising System; ANAPLAN = Anaplan Merchandise Planning; CENTRIC = Centric PLM; MANUAL = manually entered override. Used for data lineage tracking in the Databricks Silver Layer.. Valid values are `ORM|ANAPLAN|CENTRIC|MANUAL`',
    `sourcing_country_code` STRING COMMENT 'ISO 3166-1 Alpha-3 country code of the primary manufacturing/sourcing country for this assortment plan (e.g., BGD=Bangladesh, VNM=Vietnam, CHN=China). Used for landed duty paid (LDP) cost modeling, HS Code tariff classification, and GSP eligibility assessment in SAP S/4HANA MM and Infor PLM sourcing.. Valid values are `^[A-Z]{3}$`',
    `str_target_pct` DECIMAL(18,2) COMMENT 'Target Sell-Through Rate (STR) for the assortment plan, expressed as a percentage of units sold versus units received. STR = (Units Sold / Units Received) × 100. Used to set end-of-season inventory clearance expectations and validate OTB buy depth in Oracle Retail and Anaplan.',
    `style_count_planned` STRING COMMENT 'Number of distinct styles (parent product silhouettes) planned in the assortment, independent of colorway or size. Style count is a key assortment breadth metric used by merchants to balance newness versus carry-forward depth in collection planning.',
    `sustainability_certified` BOOLEAN COMMENT 'Indicates whether the assortment plan requires sustainability certification compliance (True) such as GOTS (Global Organic Textile Standard), OEKO-TEX Standard 100, or BCI (Better Cotton Initiative). Drives supplier qualification requirements in Infor PLM sourcing and compliance reporting.',
    `total_sku_count_planned` STRING COMMENT 'Total number of distinct SKUs (Stock Keeping Units) planned within this assortment, representing the breadth of the assortment. Includes all style-color-size combinations. Used to assess assortment productivity and compare planned vs. actual SKU rationalization outcomes.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the assortment plan record in the source system or Silver Layer. Tracks plan revisions, OTB reforecasts, and status transitions. Serves as the RECORD_AUDIT_UPDATED for this entity. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `version_number` STRING COMMENT 'Incremental version number of the assortment plan, starting at 1. Incremented each time the plan is revised (e.g., OTB reforecast, style additions/deletions). Enables version history tracking and comparison of plan iterations in Oracle Retail and Anaplan.',
    `wos_target` DECIMAL(18,2) COMMENT 'Target Weeks of Supply (WOS) for the assortment plan, representing the planned number of weeks of inventory coverage at the expected rate of sale. WOS = On-Hand Units / Average Weekly Sales. Used to calibrate buy depth and replenishment triggers in Oracle Retail allocation module.',
    CONSTRAINT pk_assortment_plan PRIMARY KEY(`assortment_plan_id`)
) COMMENT 'Master assortment planning entity capturing the seasonal merchandise assortment strategy by department, class, and subclass. Defines which styles, colorways, and sizes will be carried per channel and store cluster, aligned with OTB budgets and collection planning cycles. Sourced from Oracle Retail Merchandising System assortment planning module.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`collection_plan` (
    `collection_plan_id` BIGINT COMMENT 'Unique system-generated identifier for the seasonal collection plan record. Primary key for the collection_plan data product.',
    `brand_id` BIGINT COMMENT 'Reference to the brand under which this collection is planned and marketed (e.g., athletic, lifestyle, luxury sub-brand). Supports multi-brand portfolio planning and brand-level GMROI reporting.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Collection plans are coordinated with marketing campaigns for go-to-market execution. Merchandisers need to align first delivery dates, sell windows, and channel allocation with campaign flights. This',
    `collection_id` BIGINT COMMENT 'Foreign key linking to product.collection. Business justification: A collection_plan is the merchandising planning document for a specific product collection. collection_code and collection_name are denormalized from product.collection. This FK enforces referential i',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Collection development costs (design, sampling, line review, travel) are charged to merchandising cost centers. Finance requires this link to allocate collection planning expenses and track budget vs ',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Collections are designed for target customer segments (athleisure for active millennials, workwear for professionals). Segment personas inform design briefs, price architecture, and channel allocation',
    `distribution_center_id` BIGINT COMMENT 'Foreign key linking to logistics.distribution_center. Business justification: Inbound logistics capacity planning: collection delivery windows (first_delivery_date, last_delivery_date) must be tied to a receiving DC for inbound scheduling and throughput capacity management. App',
    `division_id` BIGINT COMMENT 'Reference to the merchandise division (e.g., Womens, Mens, Kids, Accessories) to which this collection plan belongs. Aligns with Oracle Retail Merchandising System merchandise hierarchy.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Collection plans contain planned_revenue_amount, planned_cogs_amount, and planned_gross_margin_pct that map to GL accounts. Finance uses GL account assignment on collection plans for revenue and COGS ',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Collection plans have department_id but no FK to merchandise_hierarchy master. Adding merchandise_hierarchy_id FK normalizes merchandise classification and removes redundant department_id. FK will ref',
    `otb_budget_id` BIGINT COMMENT 'Foreign key linking to merchandising.otb_budget. Business justification: Collection plans reference OTB budget amounts but have no FK to otb_budget master. Adding otb_budget_id FK normalizes budget reference and removes redundant otb_budget_amount. FK will reference mercha',
    `production_factory_id` BIGINT COMMENT 'Foreign key linking to production.factory. Business justification: Collection plans specify factory partners based on technical capability, quality standards, and capacity. Critical for collection development, costing, and production timeline planning.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Collections generate revenue by brand/channel, tracked via profit centers for margin analysis. Financial reporting requires linking planned collection revenue and gross margin to profit centers for br',
    `rfq_id` BIGINT COMMENT 'Foreign key linking to sourcing.rfq. Business justification: Collection plans are the upstream commercial brief that triggers RFQ activity. Sourcing teams issue RFQs referencing the collection plan to identify vendors for the collection. This link enables colle',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Collection plans are seasonal by nature; season_code and season_year exist but no FK to season master. Adding season_id FK normalizes season reference and removes redundant attributes. FK will referen',
    `approved_by` STRING COMMENT 'Name or identifier of the business stakeholder (e.g., VP Merchandising, Creative Director) who formally approved this collection plan. Supports audit trail and governance requirements.',
    `approved_date` DATE COMMENT 'Date on which the collection plan received formal business approval. Marks the transition from planning to execution phase and triggers downstream T&A calendar activities.',
    `channel_allocation_strategy` STRING COMMENT 'Planned channel distribution strategy for this collection. DTC (Direct-to-Consumer) First = prioritize own retail and e-commerce; Wholesale First = prioritize wholesale partners; Balanced = equal distribution. Drives allocation decisions in Oracle Retail and Salesforce Commerce Cloud.. Valid values are `omnichannel|dtc_first|wholesale_first|retail_only|ecommerce_only|balanced`',
    `collection_theme` STRING COMMENT 'Descriptive thematic concept or creative narrative for the collection (e.g., Urban Nomad, Coastal Luxe, Performance Elevated). Guides design direction, marketing storytelling, and visual merchandising.',
    `collection_type` STRING COMMENT 'Classification of the collection by commercial strategy. Mainline = full seasonal assortment; Capsule = focused limited assortment; Collaboration = co-branded with external partner; Limited_Edition = restricted volume; Carry_Over = NOS (Never Out of Stock) continuity styles; Core = foundational basics.. Valid values are `mainline|capsule|collaboration|limited_edition|carry_over|core`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this collection plan record was first created in the system. Provides audit trail for record origination and supports data lineage tracking in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary planning amounts in this collection plan (e.g., USD, EUR, GBP). Ensures consistent financial reporting across multi-currency operations.. Valid values are `^[A-Z]{3}$`',
    `design_brief_url` STRING COMMENT 'URL or document path to the creative design brief for this collection plan stored in Centric PLM or a connected document management system. Provides access to mood boards, color palettes, and thematic direction.',
    `dtc_allocation_pct` DECIMAL(18,2) COMMENT 'Planned percentage of total collection inventory allocated to Direct-to-Consumer (DTC) channels (own retail stores and e-commerce). Expressed as a decimal (e.g., 0.6000 = 60%). Used in channel allocation planning.',
    `first_delivery_date` DATE COMMENT 'Planned date of the first merchandise delivery to distribution centers or stores for this collection. Anchors the T&A (Time and Action) calendar and drives pre-production planning milestones.',
    `gender_target` STRING COMMENT 'Primary gender demographic target for this collection plan. Drives assortment architecture, sizing standards, and marketing segmentation. Aligns with Oracle Retail merchandise hierarchy gender classification.. Valid values are `womens|mens|unisex|kids|girls|boys`',
    `imu_target_pct` DECIMAL(18,2) COMMENT 'Target Initial Markup (IMU) percentage for the collection, representing the planned markup from cost to MSRP at the time of first receipt. A foundational pricing metric in merchandise financial planning.',
    `last_delivery_date` DATE COMMENT 'Planned date of the final merchandise delivery for this collection. Defines the end of the inbound supply window and informs markdown timing and end-of-season clearance planning.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this collection plan record. Supports change tracking, incremental data loading, and audit compliance in the Databricks Silver Layer.',
    `line_architecture_version` STRING COMMENT 'Version identifier for the line architecture document associated with this collection plan (e.g., v1.0, v2.3). Tracks iterative changes to style count, category mix, and price tier targets during the planning process in Centric PLM.. Valid values are `^v[0-9]+.[0-9]+$`',
    `otb_lock_date` DATE COMMENT 'Date on which the OTB (Open-to-Buy) budget for this collection plan is locked and committed. After this date, budget changes require formal approval. Managed in Anaplan Merchandise Planning.',
    `plan_status` STRING COMMENT 'Current lifecycle status of the collection plan record. Drives workflow routing in Centric PLM and Anaplan. Draft = initial creation; In_Review = pending creative/commercial sign-off; Approved = locked for production; Active = in-season execution; Closed = season ended; Cancelled = plan abandoned.. Valid values are `draft|in_review|approved|active|closed|cancelled`',
    `planned_aur_amount` DECIMAL(18,2) COMMENT 'Planned Average Unit Retail (AUR) price for the collection in the planning currency. Represents the expected average selling price per unit across all styles and channels, used in revenue and unit planning.',
    `planned_cogs_amount` DECIMAL(18,2) COMMENT 'Total planned Cost of Goods Sold (COGS) for this collection plan in the planning currency. Used to calculate planned gross margin and GMROI targets in Anaplan financial planning.',
    `planned_gross_margin_pct` DECIMAL(18,2) COMMENT 'Planned gross margin percentage for the collection, expressed as a decimal (e.g., 0.6200 = 62.00%). Derived from planned revenue and COGS targets; stored as a planning input in Anaplan to support IMU (Initial Markup) and MMU (Maintained Markup) targets.',
    `planned_revenue_amount` DECIMAL(18,2) COMMENT 'Total planned net sales revenue target for this collection plan in the planning currency. Used as the top-line financial KPI for merchandise financial planning and GMROI optimization in Anaplan.',
    `planned_str_pct` DECIMAL(18,2) COMMENT 'Target Sell-Through Rate (STR) for the collection, expressed as a decimal (e.g., 0.8500 = 85%). Represents the planned percentage of received inventory expected to sell at full price or planned markdown cadence before end of season.',
    `price_tier_distribution` STRING COMMENT 'Planned percentage distribution of styles across price tiers (e.g., Entry:20%|Mid:50%|Premium:30%). Guides assortment architecture to balance accessibility and margin. Stored as a structured string; detailed tier breakdowns managed in Anaplan.',
    `product_category_mix` STRING COMMENT 'Planned distribution of styles across product categories within the collection (e.g., Tops:35%|Bottoms:25%|Outerwear:20%|Footwear:15%|Accessories:5%). Stored as a structured string; detailed breakdowns managed in Anaplan and Centric PLM.',
    `range_review_date` DATE COMMENT 'Scheduled date for the formal range review meeting where the collection plan is presented to commercial and creative stakeholders for approval. A key milestone in the T&A (Time and Action) calendar.',
    `season_type` STRING COMMENT 'Classification of the retail season type for this collection plan. Drives line architecture, delivery cadence, and OTB budget allocation. [ENUM-REF-CANDIDATE: Spring/Summer|Fall/Winter|Resort|Pre-Fall|Holiday|Cruise — promote to reference product if additional seasons are added]. Valid values are `Spring/Summer|Fall/Winter|Resort|Pre-Fall|Holiday|Cruise`',
    `sell_end_date` DATE COMMENT 'Planned date when the collection is retired from active selling. Triggers end-of-season markdown strategy and clearance allocation. Effective-until date for the collections commercial lifecycle.',
    `sell_start_date` DATE COMMENT 'Planned date when the collection becomes available for sale to consumers across channels. Aligns with marketing campaign launch and store floor set dates. Effective-from date for the collections commercial lifecycle.',
    `sustainability_rating` STRING COMMENT 'Planned sustainability certification tier for the collection based on material sourcing and production standards. Reflects compliance with GOTS, BCI, OEKO-TEX, and FLA standards. Drives supplier selection and marketing claims.. Valid values are `none|bronze|silver|gold|platinum`',
    `sustainable_material_pct` DECIMAL(18,2) COMMENT 'Planned percentage of styles in the collection using certified sustainable materials (organic cotton, recycled polyester, BCI cotton, etc.). Expressed as a decimal (e.g., 0.4000 = 40%). Supports ESG reporting and FTC textile labeling compliance.',
    `target_market_region` STRING COMMENT 'Primary geographic market region(s) for which this collection is planned (e.g., NAM, EMEA, APAC, GLOBAL). Influences sizing standards, labeling requirements, and channel allocation strategy. [ENUM-REF-CANDIDATE: NAM|EMEA|APAC|LATAM|GLOBAL|DOMESTIC — promote to reference product]',
    `target_sku_count` STRING COMMENT 'Planned total number of SKUs (Stock Keeping Units) across all styles, colors, and sizes in this collection. Drives warehouse capacity planning, OTB budget, and assortment depth decisions.',
    `target_style_count` STRING COMMENT 'Planned number of distinct styles (SKU families) to be included in this collection. A key line architecture metric used to manage assortment breadth and design resource allocation in Centric PLM.',
    `wholesale_allocation_pct` DECIMAL(18,2) COMMENT 'Planned percentage of total collection inventory allocated to wholesale and distribution partners. Expressed as a decimal (e.g., 0.4000 = 40%). Complements DTC allocation to sum to 100% of planned inventory.',
    CONSTRAINT pk_collection_plan PRIMARY KEY(`collection_plan_id`)
) COMMENT 'Seasonal collection planning master record defining the thematic merchandise collection (e.g., Spring/Summer, Fall/Winter, Resort, Pre-Fall) including line architecture, style count targets, price tier distribution, and channel allocation strategy. Managed in Centric PLM and Anaplan, bridging creative direction with commercial planning.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`otb_budget` (
    `otb_budget_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each Open-to-Buy (OTB) budget master record in the Databricks Silver Layer. Primary key for the otb_budget data product.',
    `cluster_id` BIGINT COMMENT 'Foreign key linking to store.store_cluster. Business justification: OTB budgets in apparel are built at store cluster level for cluster-wide open-to-buy management (e.g., outlet cluster OTB vs. full-price cluster OTB). Cluster-level OTB planning is a named merchandisi',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Multi-entity apparel companies scope OTB budgets to a legal entity (company code) for statutory financial reporting and intercompany inventory transfer planning. Finance requires company code on OTB b',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: OTB budgets require cost center assignment for departmental budget control and overhead allocation. Finance uses cost center on OTB budgets to track planned receipt costs by department and reconcile a',
    `distribution_center_id` BIGINT COMMENT 'Foreign key linking to logistics.distribution_center. Business justification: DC-level OTB receipt planning for wholesale and DTC channels: OTB budgets are planned by DC to manage inventory flow into specific fulfillment nodes. Apparel planners build DC-level OTB to align plann',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: OTB budgets drive planned receipt accruals posted to specific GL accounts. Finance reconciles OTB actual receipts against GL for inventory receipt accruals and period-close. Apparel finance teams requ',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: OTB budgets are maintained within a specific accounting ledger for period-close reconciliation of planned vs. actual receipts. Multi-GAAP apparel companies require ledger assignment on OTB budgets to ',
    `merchandise_financial_plan_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_financial_plan. Business justification: OTB budgets are the tactical monthly execution of the strategic merchandise financial plan. The MFP sets top-down financial targets (planned sales, COGS, GM%, IMU%, markdown budget) for a season/depar',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: OTB budgets have department_id, class_id but no FK to merchandise_hierarchy master. Adding merchandise_hierarchy_id FK normalizes merchandise classification and removes redundant hierarchy attributes.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: OTB budgets drive planned receipts that directly impact divisional P&L. Finance requires profit center assignment on OTB budgets to reconcile planned inventory investment against divisional gross marg',
    `retail_store_id` BIGINT COMMENT 'Reference to the channel or location (e.g., retail store, e-commerce, wholesale) for which this OTB budget is defined. Enables channel-level OTB tracking across DTC and wholesale.',
    `season_id` BIGINT COMMENT 'Reference to the merchandise season (e.g., Spring/Summer 2025, Fall/Winter 2025) to which this OTB budget belongs. Drives seasonal buy plan alignment in Anaplan.',
    `actual_receipts_cost` DECIMAL(18,2) COMMENT 'The actual merchandise receipt value at cost consumed by confirmed purchase orders (POs) for the OTB budget month to date. Used for open-to-buy cost-basis tracking and cash flow management. Expressed in the operating currency.',
    `actual_receipts_retail` DECIMAL(18,2) COMMENT 'The actual merchandise receipt value at retail price consumed by confirmed buy plans and purchase orders (POs) for the OTB budget month to date. Compared against planned receipts to compute remaining OTB. Expressed in the operating currency.',
    `alert_threshold_percent` DECIMAL(18,2) COMMENT 'The variance threshold percentage (e.g., 0.10 = 10%) at which a merchant alert is triggered for this OTB budget record. When actual receipts or sales deviate from plan by more than this threshold, an alert is raised for merchant review and OTB recalculation.',
    `alert_triggered` BOOLEAN COMMENT 'Indicates whether a merchant alert has been triggered for this OTB budget record due to variance exceeding the defined alert threshold. True = alert active and pending merchant review; False = within acceptable variance range.',
    `anaplan_model_code` STRING COMMENT 'The unique identifier of the Anaplan model and workspace from which this OTB budget record was sourced. Enables traceability back to the originating Anaplan planning model for reconciliation and audit.',
    `approved_by` STRING COMMENT 'The name or employee identifier of the merchant or planning manager who approved this OTB budget record. Required for financial control governance and audit trail.',
    `approved_date` DATE COMMENT 'The date on which this OTB budget record was formally approved by the merchant or planning manager. Marks the transition from submitted to approved status and authorizes buying activity.',
    `bom_inventory_cost` DECIMAL(18,2) COMMENT 'The value of on-hand inventory at cost (landed duty paid) at the beginning of the OTB budget month. Used for COGS tracking and gross margin analysis. Expressed in the operating currency.',
    `bom_inventory_retail` DECIMAL(18,2) COMMENT 'The value of on-hand inventory at retail (selling) price at the beginning of the OTB budget month. Used as the opening inventory position in the OTB formula: OTB = Planned EOM Inventory + Planned Sales + Planned Markdowns - BOM Inventory. Expressed in the operating currency.',
    `budget_month` STRING COMMENT 'The calendar month (1–12) to which this OTB budget record applies. OTB is recalculated monthly; this field identifies the specific planning month within the budget year.',
    `budget_status` STRING COMMENT 'Current lifecycle state of the OTB budget record. Draft: under construction by planner. Submitted: pending merchant approval. Approved: authorized for buying. Locked: frozen for the period. Closed: period ended. Revised: re-opened for adjustment.. Valid values are `draft|submitted|approved|locked|closed|revised`',
    `budget_version` STRING COMMENT 'Version number of the OTB budget record, incremented each time the budget is revised or re-submitted. Supports version control and audit trail for merchandise financial planning changes in Anaplan.',
    `budget_year` STRING COMMENT 'The fiscal or calendar year (e.g., 2025) to which this OTB budget record applies. Used for annual merchandise financial planning and year-over-year variance analysis.',
    `channel_type` STRING COMMENT 'The distribution channel for which this OTB budget is defined. Retail: physical stores. E-Commerce: digital storefront. Wholesale: B2B partners. DTC (Direct-to-Consumer): brand-owned channels. Outlet: off-price stores.. Valid values are `retail|ecommerce|wholesale|dtc|outlet`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this OTB budget record was first created in the Databricks Silver Layer. Supports data lineage, audit trail, and compliance with IFRS/GAAP record-keeping requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this OTB budget record (e.g., USD, EUR, GBP). Ensures consistent currency denomination across retail and cost values.. Valid values are `^[A-Z]{3}$`',
    `effective_end_date` DATE COMMENT 'The last date through which this OTB budget record is effective. Typically the last day of the budget month. After this date, the budget is closed and actuals are reconciled.',
    `effective_start_date` DATE COMMENT 'The first date from which this OTB budget record is effective and binding for merchandise purchasing decisions. Typically the first day of the budget month.',
    `eom_inventory_target_retail` DECIMAL(18,2) COMMENT 'The planned ending inventory value at retail price at the end of the OTB budget month. This is the target stock position that feeds into the next months BOM inventory and is a key driver of the OTB formula. Expressed in the operating currency.',
    `imu_percent` DECIMAL(18,2) COMMENT 'The Initial Markup (IMU) percentage applied to convert retail values to cost values for this OTB budget period. IMU = (Retail - Cost) / Retail. Used to derive OTB at cost from OTB at retail and to assess margin health.',
    `last_recalculation_timestamp` TIMESTAMP COMMENT 'The exact date and time when the OTB budget values were last recalculated in Anaplan. Supports audit trail and ensures merchants are working with the most current OTB position.',
    `notes` STRING COMMENT 'Free-text notes entered by the merchant or planner to document assumptions, exceptions, or rationale for OTB budget decisions (e.g., promotional event impact, supply chain disruption, vendor delay). Supports audit trail and planning transparency.',
    `otb_cost` DECIMAL(18,2) COMMENT 'The remaining open-to-buy dollars at cost available for the OTB budget month. Derived from OTB at retail adjusted by the Initial Markup (IMU) percentage. Used for purchase order (PO) commitment and cash flow management. Expressed in the operating currency.',
    `otb_retail` DECIMAL(18,2) COMMENT 'The remaining open-to-buy dollars at retail price available for the OTB budget month. Calculated as: Planned EOM Inventory + Planned Sales + Planned Markdowns - BOM Inventory - Actual Receipts at Retail. A positive value indicates buying capacity; negative indicates over-bought. Expressed in the operating currency.',
    `planned_gmroi` DECIMAL(18,2) COMMENT 'The planned Gross Margin Return on Investment (GMROI) for the OTB budget period. GMROI = Gross Margin / Average Inventory at Cost. Measures the return generated per dollar of inventory investment. Used to prioritize department and class-level OTB allocations.',
    `planned_markdown_retail` DECIMAL(18,2) COMMENT 'The planned markdown (MD) dollar amount at retail for the OTB budget month. Markdowns reduce the retail inventory value and are a key input to the OTB formula and Maintained Markup (MMU) calculation. Expressed in the operating currency.',
    `planned_receipts_cost` DECIMAL(18,2) COMMENT 'The total planned merchandise receipt value at cost (landed duty paid / LDP) for the OTB budget month. Used for cash flow planning, purchase order (PO) commitment tracking, and COGS forecasting. Expressed in the operating currency.',
    `planned_receipts_retail` DECIMAL(18,2) COMMENT 'The total planned merchandise receipt value at retail price for the OTB budget month. Represents the maximum retail value of goods the merchant plans to receive. Expressed in the operating currency.',
    `planned_sales_retail` DECIMAL(18,2) COMMENT 'The planned net sales revenue at retail price for the OTB budget month, as defined in the merchandise financial plan. Drives the OTB calculation and sell-through rate (STR) targets. Expressed in the operating currency.',
    `planned_sales_units` STRING COMMENT 'The planned number of units to be sold during the OTB budget month. Used alongside planned sales at retail to derive the Average Unit Retail (AUR) and validate unit-level buy quantities.',
    `planned_sell_through_rate` DECIMAL(18,2) COMMENT 'The planned Sell-Through Rate (STR) for the OTB budget month, expressed as a decimal (e.g., 0.75 = 75%). STR = Units Sold / (Beginning Inventory Units + Received Units). Used to validate receipt plans and assess inventory productivity.',
    `planned_weeks_of_supply` DECIMAL(18,2) COMMENT 'The planned Weeks of Supply (WOS) at the end of the OTB budget month. WOS = EOM Inventory Units / Average Weekly Sales Units. Used to assess inventory coverage and prevent stockouts or overstock situations.',
    `recalculation_trigger_date` DATE COMMENT 'The date on which the weekly OTB recalculation was last triggered for this budget record. OTB is recalculated weekly in Anaplan based on updated actual receipts, sales actuals, and revised forecasts.',
    `source_system` STRING COMMENT 'The operational system of record from which this OTB budget record originated. Anaplan is the primary planning system; Oracle Retail provides actuals integration; SAP S/4HANA provides cost and PO data; Manual indicates planner-entered overrides.. Valid values are `anaplan|oracle_retail|sap_s4hana|manual`',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this OTB budget record was last modified in the Databricks Silver Layer. Tracks the most recent update for change management, audit trail, and downstream pipeline refresh detection.',
    `variance_receipts_retail` DECIMAL(18,2) COMMENT 'The variance between planned receipts at retail and actual receipts at retail for the OTB budget month. Positive = under-received vs plan; Negative = over-received vs plan. Triggers merchant alerts when variance exceeds the defined threshold. Expressed in the operating currency.',
    `variance_sales_retail` DECIMAL(18,2) COMMENT 'The variance between planned sales at retail and actual sales at retail for the OTB budget month. Used to assess sales performance against plan and trigger OTB recalculation when variance exceeds the alert threshold. Expressed in the operating currency.',
    CONSTRAINT pk_otb_budget PRIMARY KEY(`otb_budget_id`)
) COMMENT 'Open-to-Buy (OTB) budget master record tracking the planned versus actual merchandise purchasing budget by department, class, season, and month. Captures beginning-of-month (BOM) inventory at retail and cost, planned sales, planned markdowns, planned receipts, actual receipts consumed by buy plans, ending inventory targets, and remaining open-to-buy dollars. Includes weekly OTB recalculation triggers and variance thresholds for merchant alerts. Core financial control mechanism preventing over-buying and ensuring inventory investment aligns with sales plans. Managed in Anaplan with Oracle Retail integration.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`buy_plan` (
    `buy_plan_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the seasonal merchandise buy plan record. Primary key for the buy_plan data product in the Databricks Silver Layer.',
    `assortment_plan_id` BIGINT COMMENT 'Foreign key linking to merchandising.assortment_plan. Business justification: Buy plans execute the assortment plan by committing to specific purchase quantities, vendors, costs, and receipt timing. The assortment_plan defines WHAT to buy (styles, SKU counts, target units); the',
    `vendor_quote_id` BIGINT COMMENT 'Foreign key linking to sourcing.vendor_quote. Business justification: Buy plans are awarded based on accepted vendor quotes. Tracks which specific quote was selected for procurement, enabling cost reconciliation and vendor performance tracking. Essential for procurement',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Buy plans allocate inventory to support marketing campaigns. Buyers need campaign timing, expected conversion lift, and channel mix to size buys and set receipt dates. This link enables campaign-drive',
    `collection_id` BIGINT COMMENT 'Foreign key linking to product.collection. Business justification: Buy plans are executed for specific product collections in apparel. This FK enables collection-level buy analysis, OTB tracking by collection, and collection performance vs. buy plan reporting — stand',
    `colorway_id` BIGINT COMMENT 'Foreign key linking to product.colorway. Business justification: Buyers in apparel commit to specific colorways within a style — color selection is a distinct buying decision. buy_plan has colorway_count as a metric but no colorway FK. This link supports colorway-l',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Buy plan costs (product development, sourcing overhead, sample costs) are allocated to merchandising cost centers. Finance requires this link to track departmental expenses and allocate sourcing costs',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Buy plans contain FOB cost, LDP cost, and planned total cost that map to inventory and COGS GL accounts. Finance uses GL account assignment on buy plans for purchase commitment reporting, landed cost ',
    `hs_code_id` BIGINT COMMENT 'Foreign key linking to logistics.hs_code. Business justification: Import duty classification and trade compliance: buy_plan.hs_code is a denormalized plain attribute. Proper FK to logistics.hs_code enables duty rate lookup, Section 301 tariff flagging, and GSP eligi',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Buy plans generate purchase commitments recorded in a specific accounting ledger. Finance uses ledger assignment on buy plans for open-to-buy commitment tracking, purchase accruals, and period-close r',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Buy plans have department_id, class_id, subclass_id but no FK to merchandise_hierarchy master. Adding merchandise_hierarchy_id FK normalizes merchandise classification and removes redundant hierarchy ',
    `otb_budget_id` BIGINT COMMENT 'Reference to the Open-to-Buy budget authorization record that funds this buy plan. Links financial OTB authorization in Anaplan to actual purchase order execution in SAP S/4HANA MM.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Buy plans drive inventory investment and future margin by channel/brand, tracked via profit centers. Financial planning requires linking buy plan commitments to profit centers for forward-looking marg',
    `retail_store_id` BIGINT COMMENT 'Reference to the destination location (store, distribution center, or warehouse) for which this buy plan is created. Used for allocation planning and receipt flow scheduling in Manhattan Associates WMS.',
    `rfq_id` BIGINT COMMENT 'Foreign key linking to sourcing.rfq. Business justification: Buy plans originate from RFQ processes when sourcing new styles. Tracks which RFQ led to the buy decision, enabling cost variance analysis between quoted and planned costs. Essential for procurement a',
    `routing_guide_id` BIGINT COMMENT 'Foreign key linking to logistics.routing_guide. Business justification: LDP cost modeling during buy planning: buyers select a routing guide to estimate freight cost, transit time, and incoterm compliance per lane. Apparel planners routinely embed routing guide selection ',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Buy plans are seasonal procurement plans; season_code exists but no FK to season master. Adding season_id FK normalizes season reference and removes redundant season_code. FK will reference merchandis',
    `sourcing_purchase_order_id` BIGINT COMMENT 'Foreign key linking to sourcing.sourcing_purchase_order. Business justification: Buy plans convert to sourcing POs upon approval. Tracks execution of planned buys and enables plan-vs-actual reconciliation for cost, timing, and quantity variances. Critical for procurement performan',
    `style_id` BIGINT COMMENT 'Reference to the product style being planned in this buy plan. Links to the PLM-managed style master in Infor PLM / Centric PLM. A buy plan may cover one or multiple styles depending on planning granularity.',
    `supplier_factory_id` BIGINT COMMENT 'Foreign key linking to supplier.supplier_factory. Business justification: Each buy plan in apparel sourcing is executed at a specific supplier factory. This link enables factory-level capacity checks, compliance status validation, and audit clearance verification before a b',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor_agreement. Business justification: Buy plans must reference the governing vendor agreement to enforce contractual terms (payment terms, MOQ, incoterms, exclusivity). Apparel buyers validate agreement validity and compliance before fina',
    `vendor_id` BIGINT COMMENT 'Reference to the primary supplier/vendor committed to fulfilling this buy plan. Links to the vendor master in SAP S/4HANA MM. Drives purchase order creation and supplier commitment tracking.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the merchandise planning manager or director who approved this buy plan. Required for audit trail and financial authorization compliance.',
    `approved_date` DATE COMMENT 'Date on which the buy plan was formally approved by the authorized merchandise planning manager. Triggers OTB budget consumption and purchase order release authorization in SAP S/4HANA MM.',
    `buy_plan_number` STRING COMMENT 'Externally-known business identifier for the buy plan, used in cross-system communication with Oracle Retail Merchandising System, Anaplan, and SAP S/4HANA MM. Follows the format BP-{YEAR}-{ALPHANUMERIC_CODE}.. Valid values are `^BP-[0-9]{4}-[A-Z0-9]{6,12}$`',
    `channel` STRING COMMENT 'Merchandise distribution channel for which this buy plan is created. Drives channel-specific assortment and allocation strategies. DTC (Direct-to-Consumer) includes both retail stores and e-commerce. [ENUM-REF-CANDIDATE: retail|ecommerce|wholesale|dtc|outlet|marketplace — promote to reference product]. Valid values are `retail|ecommerce|wholesale|dtc|outlet`',
    `colorway_count` STRING COMMENT 'Number of distinct colorways (color/material combinations) included in this buy plan. Used for assortment breadth analysis and collection planning in Oracle Retail Merchandising System.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country where the merchandise is manufactured. Required for customs duty calculation, HS Code classification, GSP eligibility, and FTC textile labeling compliance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this buy plan record was first created in the system. Supports audit trail, data lineage, and compliance reporting requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this buy plan (e.g., USD, EUR, GBP). Supports multi-currency sourcing operations across global vendor base.. Valid values are `^[A-Z]{3}$`',
    `ex_factory_date` DATE COMMENT 'Planned date on which finished goods are expected to leave the manufacturing facility (ex-factory). Key milestone in the T&A (Time and Action) calendar. Used to calculate transit lead times and planned receipt dates.',
    `floor_set_date` DATE COMMENT 'Planned date for merchandise to be on the retail floor or live on the e-commerce site. Aligns with the seasonal collection launch calendar and marketing campaign timing.',
    `fob_cost` DECIMAL(18,2) COMMENT 'Free on Board unit cost agreed with the vendor, representing the product cost at the point of origin before freight, duties, and insurance. Used as the base cost in COGS and IMU calculations. Expressed in the plan currency.',
    `imu_percent` DECIMAL(18,2) COMMENT 'Initial Markup percentage calculated as (MSRP - LDP Cost) / MSRP * 100. Represents the planned gross margin at the time of the buy decision. Key financial KPI in merchandise financial planning reviewed in Anaplan.',
    `in_dc_date` DATE COMMENT 'Planned date for merchandise to arrive at the distribution center. Drives inbound scheduling in Manhattan Associates WMS and store allocation timing. Critical for floor-set and launch date compliance.',
    `incoterms` STRING COMMENT 'International Commercial Terms (Incoterms) governing the transfer of risk and cost responsibility between buyer and vendor for this buy plan shipment. Determines the point at which ownership and risk transfer. [ENUM-REF-CANDIDATE: FOB|CIF|EXW|DDP|FCA|CFR|DAP — 7 candidates stripped; promote to reference product]',
    `is_exclusive` BOOLEAN COMMENT 'Flag indicating whether the merchandise in this buy plan is an exclusive product (e.g., retailer-exclusive colorway, channel-exclusive style). Exclusives may have different MOQ, pricing, and allocation rules.',
    `is_nos` BOOLEAN COMMENT 'Flag indicating whether this buy plan is for a Never Out of Stock (NOS) / core replenishment item that is carried across multiple seasons, as opposed to a seasonal fashion buy. NOS items follow continuous replenishment planning rules.',
    `ldp_cost` DECIMAL(18,2) COMMENT 'Landed Duty Paid unit cost inclusive of FOB cost, ocean/air freight, customs duties, insurance, and port handling charges. Represents the true total cost of goods at the destination DC. Used for COGS, GMROI, and IMU calculations.',
    `moq` STRING COMMENT 'Minimum Order Quantity committed to the vendor for this buy plan. Sourced from vendor negotiation terms in SAP S/4HANA MM. Buy plan units must meet or exceed MOQ to trigger purchase order creation.',
    `msrp` DECIMAL(18,2) COMMENT 'Manufacturers Suggested Retail Price for the planned style. Used as the reference retail price for IMU (Initial Markup) and AUR (Average Unit Retail) calculations in merchandise financial planning.',
    `notes` STRING COMMENT 'Free-text field for merchandiser annotations, buyer comments, or special instructions related to this buy plan (e.g., vendor negotiation notes, allocation constraints, marketing tie-ins).',
    `payment_terms` STRING COMMENT 'Vendor payment terms agreed for this buy plan (e.g., LC 90 days, Net 60, FOB 30). Includes Letter of Credit (LC) terms where applicable. Sourced from SAP S/4HANA MM vendor payment terms configuration.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the buy plan within the merchandise planning workflow. Drives approval routing in Anaplan and purchase order release authorization in SAP S/4HANA MM. [ENUM-REF-CANDIDATE: draft|submitted|approved|locked|cancelled|closed — promote to reference product if additional states are required]. Valid values are `draft|submitted|approved|locked|cancelled|closed`',
    `plan_type` STRING COMMENT 'Classification of the buy plan iteration. initial = first-pass seasonal buy, revised = updated after market feedback, final = locked for PO execution, carryover = NOS (Never Out of Stock) replenishment plan.. Valid values are `initial|revised|final|carryover`',
    `planned_receipt_end_date` DATE COMMENT 'Latest planned date for all merchandise receipts under this buy plan to be completed. Defines the receipt window for seasonal floor-set readiness and OTB period closure.',
    `planned_receipt_start_date` DATE COMMENT 'Earliest planned date for merchandise receipts to arrive at the destination DC or store. Drives the receipt flow schedule and warehouse inbound planning in Manhattan Associates WMS.',
    `planned_str_percent` DECIMAL(18,2) COMMENT 'Planned Sell-Through Rate (STR) percentage for this buy plan, representing the expected proportion of units sold at full price by end of season. Used as a key input for OTB budget sizing and markdown risk assessment in Anaplan.',
    `planned_total_cost` DECIMAL(18,2) COMMENT 'Total planned cost commitment for this buy plan, calculated as planned_units × ldp_cost. Represents the OTB budget consumption amount in the merchandise financial plan. Expressed in the plan currency.',
    `planned_total_retail` DECIMAL(18,2) COMMENT 'Total planned retail value of the buy plan, calculated as planned_units × MSRP. Used for OTB retail budget tracking and GMROI planning in Anaplan merchandise financial planning.',
    `planned_units` STRING COMMENT 'Total number of units planned for purchase in this buy plan across all sizes and colorways. Represents the gross buy quantity before MOQ adjustments. Used as the primary quantity driver for OTB consumption calculation.',
    `po_number` STRING COMMENT 'SAP S/4HANA MM Purchase Order number generated from this buy plan upon approval. Links the financial buy plan to the operational procurement execution. A buy plan may generate one or multiple POs.. Valid values are `^PO-[0-9]{4}-[A-Z0-9]{6,12}$`',
    `size_range` STRING COMMENT 'Size range covered by this buy plan (e.g., XS-XXL, 6-12, 28-38). Represents the full size spectrum planned for purchase. Detailed size-level quantity breakdowns are managed in the buy plan line items.',
    `sourcing_type` STRING COMMENT 'Manufacturing sourcing model for this buy plan. CMT (Cut Make Trim) = vendor provides labor only; OEM (Original Equipment Manufacturer) = vendor manufactures to spec; ODM (Original Design Manufacturer) = vendor designs and manufactures; direct = owned factory.. Valid values are `cmt|oem|odm|direct`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this buy plan record. Used for change tracking, incremental data pipeline processing, and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `wos_target` DECIMAL(18,2) COMMENT 'Target Weeks of Supply (WOS) for this buy plan, representing the planned inventory coverage in weeks at the expected rate of sale. Used to calibrate receipt flow timing and prevent over/under-buying.',
    CONSTRAINT pk_buy_plan PRIMARY KEY(`buy_plan_id`)
) COMMENT 'Seasonal merchandise buy plan capturing planned purchase quantities, costs, receipt timing, and supplier commitments by style, colorway, size, and vendor. Includes MOQ commitments, FOB and LDP cost calculations, planned receipt flow by week, and OTB budget consumption tracking. Links financial OTB authorization to actual purchase order execution. Drives procurement workflows in SAP S/4HANA MM.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`buy_plan_line` (
    `buy_plan_line_id` BIGINT COMMENT 'Unique surrogate identifier for each line-level record within a seasonal buy plan. Primary key for the buy_plan_line entity in the Databricks Silver Layer.',
    `buy_plan_id` BIGINT COMMENT 'Reference to the parent seasonal buy plan header that this line belongs to. Establishes the header-to-line relationship for Open-to-Buy (OTB) tracking and merchandise financial planning.',
    `colorway_id` BIGINT COMMENT 'Foreign key linking to product.colorway. Business justification: Buy plan lines are the most granular buying unit in apparel — style + colorway + size. colorway_code is a denormalized plain text attribute. This FK enables colorway-level buy quantity analysis, color',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Buy plan lines carry unit_cost, initial_markup_pct, and markdown_allowance_pct that map to specific GL accounts for SKU-level COGS recognition and inventory valuation. Finance requires line-level GL a',
    `hs_code_id` BIGINT COMMENT 'Foreign key linking to logistics.hs_code. Business justification: SKU-level import duty classification: buy_plan_line.hs_code is a denormalized plain attribute. Proper FK to logistics.hs_code enables per-SKU duty rate application, antidumping/countervailing duty fla',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Buy plan lines have department_id, class_id but no FK to merchandise_hierarchy master. Adding merchandise_hierarchy_id FK normalizes merchandise classification and removes redundant hierarchy attribut',
    `otb_budget_id` BIGINT COMMENT 'Reference to the Open-to-Buy (OTB) budget record against which this buy plan line is charged. Enables tracking of buy plan commitments against approved OTB budgets by department, class, and season.',
    `retail_store_id` BIGINT COMMENT 'Foreign key linking to store.retail_store. Business justification: Buy plan lines in apparel are allocated to specific stores for store-level size/color buy allocation — a named process in apparel buying. buy_plan has retail_store_id at header level, but line-level s',
    `rfq_line_id` BIGINT COMMENT 'Foreign key linking to sourcing.rfq_line. Business justification: Line-level traceability from RFQ response to buy plan execution. Critical for cost variance analysis, comparing target costs in RFQ to planned costs in buy plan. Supports vendor performance evaluation',
    `routing_guide_id` BIGINT COMMENT 'Foreign key linking to logistics.routing_guide. Business justification: Per-SKU LDP unit cost calculation: routing guide drives the freight cost component of LDP at the buy plan line level. Apparel merchants require routing guide reference at SKU level to compute accurate',
    `sku_id` BIGINT COMMENT 'Reference to the specific Stock Keeping Unit (SKU) being purchased on this buy plan line, representing the unique combination of style, color, and size.',
    `sourcing_purchase_order_line_id` BIGINT COMMENT 'Foreign key linking to sourcing.sourcing_purchase_order_line. Business justification: Line-level traceability from buy plan to actual PO. Critical for unit cost variance analysis, delivery tracking, and SKU-level plan-vs-actual reconciliation. Enables precise margin analysis and vendor',
    `style_id` BIGINT COMMENT 'Foreign key linking to product.style. Business justification: Buy plan lines reference specific styles for line-level style analysis. style_number is a denormalized plain text attribute on buy_plan_line. This FK enables style-level buy quantity analysis, style a',
    `supplier_factory_id` BIGINT COMMENT 'Foreign key linking to supplier.supplier_factory. Business justification: Apparel buy plan lines are assigned to specific factories for production execution. Factory-level assignment on each line drives capacity allocation, compliance validation, and delivery scheduling. A ',
    `vendor_cost_quote_id` BIGINT COMMENT 'Foreign key linking to sourcing.vendor_cost_quote. Business justification: Line-level cost traceability from vendor quote to buy plan. Essential for margin analysis, IMU calculation validation, and cost reconciliation. Enables comparison of quoted costs to planned costs for ',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier (vendor/manufacturer) allocated to produce and deliver the units on this buy plan line. Supports supplier allocation analysis and sourcing strategy reporting.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to production.work_order. Business justification: Line-level work order link enables granular production tracking, variance analysis between planned and produced quantities, and SKU-level delivery status. Essential for inventory accuracy and fulfillm',
    `approved_timestamp` TIMESTAMP COMMENT 'The timestamp when this buy plan line was formally approved by the merchandising team, authorizing the purchase commitment and OTB charge. Distinct from creation and update timestamps as it marks a specific business lifecycle event.',
    `channel_code` STRING COMMENT 'The distribution channel for which this buy plan line is intended: DTC (Direct-to-Consumer retail stores), WHOLESALE (wholesale partners), ECOMM (e-commerce), OUTLET, or FRANCHISE. Drives channel-specific allocation and OTB management.. Valid values are `DTC|WHOLESALE|ECOMM|OUTLET|FRANCHISE`',
    `confirmed_units` STRING COMMENT 'The number of units formally confirmed with the supplier via Purchase Order (PO). May differ from planned or revised units due to Minimum Order Quantity (MOQ) constraints or supplier capacity limitations.',
    `cost_type` STRING COMMENT 'Indicates the cost basis for the unit cost on this line: CMT (Cut Make Trim), FOB (Free on Board), LDP (Landed Duty Paid), DDP (Delivered Duty Paid), or EXW (Ex Works). Determines what logistics and duty costs are included in the unit cost figure.. Valid values are `CMT|FOB|LDP|DDP|EXW`',
    `country_of_origin` STRING COMMENT 'The ISO 3166-1 alpha-3 country code indicating where the goods on this buy plan line are manufactured. Required for customs declarations, HS Code classification, duty calculation, and FTC country-of-origin labeling compliance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this buy plan line record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail requirements and data lineage tracking.',
    `fabric_content` STRING COMMENT 'The fiber/material composition of the product on this buy plan line (e.g., 100% Cotton, 60% Polyester 40% Nylon). Required for FTC textile labeling compliance, OEKO-TEX certification tracking, and sustainability reporting under GOTS/BCI standards.',
    `initial_markup_pct` DECIMAL(18,2) COMMENT 'The Initial Markup (IMU) percentage for this buy plan line, calculated as (MSRP - Unit Cost) / MSRP. Represents the planned gross margin at full retail price before any markdowns. Key metric in merchandise financial planning.',
    `is_exclusive` BOOLEAN COMMENT 'Indicates whether this buy plan line represents an exclusive product (e.g., retailer-exclusive colorway or style) that is not available through other distribution channels. Affects pricing strategy and wholesale allocation decisions.',
    `is_never_out_of_stock` BOOLEAN COMMENT 'Indicates whether this buy plan line is designated as a Never Out of Stock (NOS) item, meaning it is a core replenishment SKU that must be continuously available. NOS items receive priority in allocation and replenishment planning.',
    `line_number` STRING COMMENT 'Sequential line number within the parent buy plan, used to order and reference individual SKU-level purchase commitments within a single seasonal buy plan.',
    `line_status` STRING COMMENT 'The current workflow status of this buy plan line, tracking its lifecycle from initial planning through receipt. [ENUM-REF-CANDIDATE: draft|submitted|approved|po_issued|in_production|shipped|received|cancelled — promote to reference product]',
    `markdown_allowance_pct` DECIMAL(18,2) COMMENT 'The planned markdown (MD) allowance percentage for this buy plan line, representing the anticipated price reduction from MSRP to clear end-of-season inventory. Used in Maintained Markup (MMU) calculations and merchandise financial planning.',
    `moq` STRING COMMENT 'The Minimum Order Quantity (MOQ) required by the supplier for this buy plan line. Constrains the minimum units that can be ordered and may cause confirmed units to differ from planned units. Critical for buy plan feasibility analysis.',
    `msrp` DECIMAL(18,2) COMMENT 'The Manufacturers Suggested Retail Price (MSRP) for the SKU on this buy plan line. Used to calculate Initial Markup (IMU) and supports wholesale pricing, retail pricing strategy, and GMROI analysis.',
    `notes` STRING COMMENT 'Free-text notes or comments associated with this buy plan line, capturing merchandiser annotations, supplier negotiation notes, or special handling instructions not captured in structured fields.',
    `original_cancel_date` DATE COMMENT 'The original date by which the purchase order for this buy plan line must be cancelled if the supplier cannot fulfill. Established at the time of initial buy plan creation as part of the Time and Action (T&A) calendar.',
    `planned_receipt_date` DATE COMMENT 'The planned date on which the units for this buy plan line are expected to be received at the distribution center or warehouse. Drives inventory flow planning, OTB timing, and Weeks of Supply (WOS) calculations.',
    `planned_sell_through_pct` DECIMAL(18,2) COMMENT 'The planned Sell-Through Rate (STR) percentage for this buy plan line, representing the expected proportion of units sold at full price or within the season. Used as a benchmark for post-season performance analysis and future buy plan calibration.',
    `planned_units` STRING COMMENT 'The total number of units planned for purchase on this buy plan line for the season. Represents the initial buy commitment before any revisions. Core quantity field for OTB tracking and inventory planning.',
    `pre_production_sample_status` STRING COMMENT 'The approval status of the Pre-Production (PP) sample for this buy plan line. PP sample approval is a prerequisite for production release in the T&A calendar. Tracked in the PLM system.. Valid values are `pending|submitted|approved|rejected|waived`',
    `product_category` STRING COMMENT 'The high-level product category for this buy plan line (e.g., Tops, Bottoms, Outerwear, Footwear, Accessories). Used for cross-category OTB analysis and assortment balance reporting.',
    `purchase_currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which the unit cost is denominated (e.g., USD, EUR, CNY). Required for multi-currency buy plan consolidation and financial reporting under IFRS/GAAP.. Valid values are `^[A-Z]{3}$`',
    `revised_cancel_date` DATE COMMENT 'The most recently revised cancel date for this buy plan line, updated during the T&A (Time and Action) calendar review process. Tracks changes to delivery commitments and supplier negotiation outcomes.',
    `revised_units` STRING COMMENT 'The most recently revised unit quantity for this buy plan line, reflecting any adjustments made after the initial plan was set. Enables tracking of buy plan changes against original commitments and OTB impact analysis.',
    `season_code` STRING COMMENT 'The merchandising season code to which this buy plan line belongs (e.g., SS25 for Spring/Summer 2025, FW25 for Fall/Winter 2025). Drives collection planning, OTB budgeting, and sell-through rate (STR) analysis by season.. Valid values are `^(SS|FW|HO|RE|CR)[0-9]{2}$`',
    `size_code` STRING COMMENT 'The size designation for this buy plan line (e.g., XS, S, M, L, XL, 28x30, 7.5). Represents the specific size within the size run being committed to in this purchase. Drives size curve analysis and allocation planning.',
    `size_run_type` STRING COMMENT 'Indicates whether this buy plan line represents a full size run, partial size run, core size run (best-selling sizes only), or extended size run (including plus/petite). Drives assortment breadth decisions and size curve planning.. Valid values are `full|partial|core|extended`',
    `unit_cost` DECIMAL(18,2) COMMENT 'The negotiated cost per unit for this buy plan line, expressed in the purchase currency. May represent CMT (Cut Make Trim) cost or FOB (Free on Board) cost depending on the sourcing arrangement. Core input for COGS and GMROI calculations.',
    `upc` STRING COMMENT 'The Universal Product Code (UPC) barcode identifier for the specific SKU on this buy plan line. Used for downstream POS scanning, warehouse receiving, and EDI transactions with suppliers.. Valid values are `^[0-9]{12,14}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this buy plan line record was last modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Tracks the most recent change for audit and data freshness monitoring.',
    CONSTRAINT pk_buy_plan_line PRIMARY KEY(`buy_plan_line_id`)
) COMMENT 'Line-level detail of the seasonal buy plan representing individual SKU-level purchase commitments within a buy plan. Captures style number, colorway, size run, planned units, unit cost (CMT/FOB), planned receipt date, and supplier allocation. Enables granular tracking of buy plan execution against OTB.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`merchandise_hierarchy` (
    `merchandise_hierarchy_id` BIGINT COMMENT 'Unique surrogate identifier for each node in the merchandise hierarchy. Primary key for the merchandise_hierarchy data product in the Oracle Retail Merchandising System (ORM) silver layer.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Merchandise hierarchy nodes (department, class, subclass) map to GL accounts for automated COGS, inventory, and revenue account determination. This is a fundamental apparel finance operational link us',
    `hs_code_id` BIGINT COMMENT 'Foreign key linking to logistics.hs_code. Business justification: Merchandise classification for import duty: merchandise_hierarchy.hs_code_prefix is a denormalized plain attribute. Proper FK to logistics.hs_code enables category-level duty rate defaulting, CPSC reg',
    `parent_hierarchy_merchandise_hierarchy_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediate parent node in the merchandise hierarchy. A Division node has a null parent; a Department references its Division; a Class references its Department; a Subclass references its Class. Enables hierarchical roll-up for OTB, GMROI, and financial planning.',
    `channel_applicability` STRING COMMENT 'Indicates which sales channels this merchandise hierarchy node applies to: all channels, retail stores, e-commerce (DTC digital), wholesale, or direct-to-consumer (DTC). Governs channel-specific assortment planning, OTB allocation, and pricing strategies in Oracle Retail and Salesforce Commerce Cloud.. Valid values are `all|retail|ecommerce|wholesale|dtc`',
    `class_code` STRING COMMENT 'Alphanumeric code identifying the Class level node within a Department (e.g., JKT for Jackets, PNT for Pants). Null for Division and Department-level records. Used in Oracle Retail for class-level assortment planning, price management, and STR analysis.. Valid values are `^[A-Z0-9]{2,10}$`',
    `class_name` STRING COMMENT 'Descriptive name of the Class (e.g., Jackets, Pants, T-Shirts, Sneakers). Null for Division and Department-level records. Displayed in Oracle Retail assortment planning, allocation, and price management modules.',
    `cpsc_regulated` BOOLEAN COMMENT 'Indicates whether products in this merchandise hierarchy node are subject to Consumer Product Safety Commission (CPSC) safety standards (e.g., childrens apparel flammability, drawstring regulations). Triggers mandatory safety testing and compliance documentation requirements in Infor PLM and quality management workflows.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this merchandise hierarchy record was first created in the Oracle Retail Merchandising System and ingested into the Databricks silver layer. Supports data lineage, audit trail, and change management tracking.',
    `department_code` STRING COMMENT 'Alphanumeric code identifying the Department level node (e.g., ACT for Activewear, OTW for Outerwear). Null for Division-level records. Used in Oracle Retail for department-level OTB budgeting, allocation strategies, and merchandise financial planning.. Valid values are `^[A-Z0-9]{2,10}$`',
    `department_name` STRING COMMENT 'Descriptive name of the Department (e.g., Activewear, Outerwear, Denim, Footwear). Null for Division-level records. Denormalized for flat reporting in assortment planning, OTB dashboards, and Anaplan merchandise financial plans.',
    `division_code` STRING COMMENT 'Alphanumeric code identifying the top-level Division to which this hierarchy node belongs (e.g., MNS for Mens, WMN for Womens, KDS for Kids). Populated at all levels for denormalized reporting and OTB budget allocation in Anaplan.. Valid values are `^[A-Z0-9]{2,10}$`',
    `division_name` STRING COMMENT 'Descriptive name of the top-level Division (e.g., Mens, Womens, Kids, Accessories). Denormalized at all hierarchy levels to support flat reporting in Oracle Retail, Anaplan, and BI dashboards without requiring joins.',
    `effective_end_date` DATE COMMENT 'The date after which this merchandise hierarchy node is no longer active for new planning, OTB, or SKU assignment. Null indicates an open-ended, currently active node. Supports hierarchy versioning and historical reporting in Oracle Retail and Anaplan.',
    `effective_start_date` DATE COMMENT 'The date from which this merchandise hierarchy node becomes effective and available for use in assortment planning, OTB budgeting, and SKU assignment in Oracle Retail Merchandising System. Supports temporal validity management for hierarchy restructuring.',
    `erp_category_code` STRING COMMENT 'Corresponding material group or product category code in SAP S/4HANA (MM module) that maps to this merchandise hierarchy node. Ensures alignment between Oracle Retail merchandise taxonomy and SAP procurement, inventory valuation, and COGS reporting.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `fiber_content_required` BOOLEAN COMMENT 'Indicates whether products in this merchandise hierarchy node require fiber content disclosure on product labels per FTC Textile and Apparel Labeling regulations. Drives compliance requirements in Infor PLM tech pack specifications and product labeling workflows.',
    `gender_affinity` STRING COMMENT 'Gender classification associated with this merchandise hierarchy node, used to segment assortments, OTB budgets, and marketing campaigns. Aligns with Oracle Retail Merchandising System division and department structures for gender-based merchandise financial planning.. Valid values are `mens|womens|unisex|kids|boys|girls`',
    `hierarchy_code` STRING COMMENT 'Externally-known alphanumeric code that uniquely identifies this hierarchy node within the Oracle Retail Merchandising System. Used as the business key in OTB budgets, assortment plans, and financial reporting across Oracle Retail and Anaplan.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `hierarchy_depth` STRING COMMENT 'Numeric depth of this node in the hierarchy tree: 1=Division, 2=Department, 3=Class, 4=Subclass. Supports hierarchical traversal, roll-up aggregation, and level-specific filtering in OTB and GMROI reporting.',
    `hierarchy_level` STRING COMMENT 'Indicates the level of this node within the four-tier merchandise classification structure: Division > Department > Class > Subclass. Governs how OTB budgets, assortment plans, and GMROI reporting are structured and rolled up in Oracle Retail Merchandising System.. Valid values are `division|department|class|subclass`',
    `hierarchy_name` STRING COMMENT 'Human-readable name of the merchandise hierarchy node (e.g., Mens Activewear, Outerwear, Footwear). Displayed in assortment planning, OTB reporting, and financial planning dashboards in Oracle Retail and Anaplan.',
    `hierarchy_status` STRING COMMENT 'Current lifecycle status of this merchandise hierarchy node. Active nodes are available for assortment planning, OTB budgeting, and SKU assignment. Inactive or archived nodes are retained for historical reporting but excluded from new planning cycles in Oracle Retail and Anaplan.. Valid values are `active|inactive|pending|archived`',
    `is_nos_eligible` BOOLEAN COMMENT 'Indicates whether products in this merchandise hierarchy node are designated as Never Out of Stock (NOS) items requiring continuous replenishment. NOS-eligible nodes receive dedicated OTB budget allocation and automated replenishment triggers in Oracle Retail and Manhattan Associates WMS.',
    `is_private_label` BOOLEAN COMMENT 'Indicates whether this merchandise hierarchy node is designated for private label (own-brand) products as opposed to national or licensed brands. Affects sourcing strategy (CMT, OEM, ODM), IMU targets, and margin planning in Infor PLM and Anaplan.',
    `labor_compliance_standard` STRING COMMENT 'Labor compliance certification standard required for suppliers producing goods in this merchandise hierarchy node (e.g., FLA, WRAP, SA8000, SEDEX). Governs supplier qualification, factory audit requirements, and sourcing decisions in SAP S/4HANA MM and Infor PLM sourcing modules.. Valid values are `fla|wrap|sa8000|sedex|none`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this merchandise hierarchy record was last updated in the Oracle Retail Merchandising System or the Databricks silver layer. Used for incremental data pipeline processing, change detection, and audit compliance.',
    `lifestyle_category` STRING COMMENT 'Lifestyle or end-use category classification for this hierarchy node, distinguishing athletic performance, lifestyle, luxury, workwear, casual, and outdoor segments. Supports brand positioning, collection planning, and targeted marketing strategies in Adobe Experience Platform and Anaplan.. Valid values are `athletic|lifestyle|luxury|workwear|casual|outdoor`',
    `markdown_strategy` STRING COMMENT 'Markdown (MD) strategy designation for this merchandise hierarchy node, indicating the planned approach to price reductions during the selling season. Governs Oracle Retail Price Management markdown rules, Anaplan financial planning assumptions, and MMU maintenance targets.. Valid values are `standard|aggressive|minimal|clearance|never`',
    `merchandise_hierarchy_description` STRING COMMENT 'Free-text business description of this merchandise hierarchy node, providing additional context about the product category, its scope, and any special planning or sourcing considerations. Maintained in Oracle Retail Merchandising System and used in buyer-facing assortment planning documentation.',
    `merchandise_type` STRING COMMENT 'Broad merchandise type classification indicating the nature of products within this hierarchy node. Drives category-specific planning rules, margin targets, and allocation strategies in Oracle Retail and Anaplan merchandise financial planning.. Valid values are `apparel|footwear|accessories|equipment|home|beauty`',
    `otb_budget_method` STRING COMMENT 'Indicates the Open-to-Buy (OTB) budget planning methodology applied to this merchandise hierarchy node: top-down (executive-driven), bottom-up (buyer-driven), or hybrid. Determines how Anaplan merchandise financial plans are structured and reconciled with Oracle Retail OTB budgets.. Valid values are `top_down|bottom_up|hybrid`',
    `plm_category_code` STRING COMMENT 'Corresponding category code in the Infor PLM or Centric PLM system that maps to this merchandise hierarchy node. Enables cross-system alignment between the Oracle Retail merchandise taxonomy and the PLM product design and BOM management classification for collection planning and tech pack organization.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `season_applicability` STRING COMMENT 'Seasonal classification indicating which selling seasons this hierarchy node is active for. Drives seasonal buy plan creation, OTB budget phasing, and collection planning cycles in Oracle Retail Merchandising System and Anaplan.. Valid values are `spring_summer|fall_winter|all_season|resort|pre_fall`',
    `sort_sequence` STRING COMMENT 'Numeric ordering sequence for displaying this hierarchy node among its siblings within the same parent. Controls the display order in Oracle Retail Merchandising System screens, assortment planning tools, and reporting dashboards.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this merchandise hierarchy record originated (e.g., ORM for Oracle Retail Merchandising System, SAP for SAP S/4HANA). Supports data lineage, master data management reconciliation, and silver layer provenance tracking in the Databricks lakehouse.. Valid values are `ORM|SAP|ANAPLAN|INFOR_PLM|CENTRIC_PLM`',
    `subclass_code` STRING COMMENT 'Alphanumeric code identifying the Subclass level node within a Class (e.g., PUFF for Puffer Jackets, WNDBRKR for Windbreakers). Null for Division, Department, and Class-level records. The most granular level for SKU assignment, OTB allocation, and STR tracking.. Valid values are `^[A-Z0-9]{2,10}$`',
    `subclass_name` STRING COMMENT 'Descriptive name of the Subclass (e.g., Puffer Jackets, Windbreakers, Slim Fit Jeans). Null for Division, Department, and Class-level records. Used in Oracle Retail for the most granular assortment planning, allocation, and markdown optimization.',
    `target_gmroi` DECIMAL(18,2) COMMENT 'Target Gross Margin Return on Investment (GMROI) for this merchandise hierarchy node, calculated as gross margin dollars divided by average inventory cost. A primary KPI for merchandise financial planning and OTB budget justification in Anaplan and Oracle Retail.',
    `target_imu_pct` DECIMAL(18,2) COMMENT 'Target Initial Markup (IMU) percentage for products within this merchandise hierarchy node, representing the planned markup from cost to MSRP at the time of first receipt. A key financial planning metric in Anaplan OTB and Oracle Retail Price Management for setting pricing strategy and GMROI targets.',
    `target_str_pct` DECIMAL(18,2) COMMENT 'Target Sell-Through Rate (STR) percentage for this merchandise hierarchy node, representing the planned proportion of received inventory sold within a season. Used in Oracle Retail and Anaplan to evaluate assortment performance, trigger markdown decisions, and set OTB buy quantities.',
    `target_wos` DECIMAL(18,2) COMMENT 'Target Weeks of Supply (WOS) for this merchandise hierarchy node, representing the planned number of weeks of inventory on hand relative to forecasted sales rate. Drives replenishment triggers, OTB phasing, and allocation strategies in Oracle Retail and Manhattan Associates WMS.',
    CONSTRAINT pk_merchandise_hierarchy PRIMARY KEY(`merchandise_hierarchy_id`)
) COMMENT 'Master reference for the merchandise classification hierarchy defining the organizational structure of product categories: Division > Department > Class > Subclass. Governs how assortments, OTB budgets, and financial plans are structured and reported. Managed in Oracle Retail Merchandising System as the foundational taxonomy.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`price_master` (
    `price_master_id` BIGINT COMMENT 'Unique surrogate identifier for each price master record in the Databricks Silver Layer. Serves as the primary key for the price_master data product.',
    `channel_id` BIGINT COMMENT 'Reference to the sales channel for which this price record is applicable (e.g., DTC retail store, e-commerce, wholesale). Supports channel-specific pricing strategies.',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Differential pricing strategies by customer segment (VIP early access pricing, employee discounts, wholesale vs retail). Segment-based price optimization and dynamic pricing models require linking pri',
    `duty_calculation_id` BIGINT COMMENT 'Foreign key linking to logistics.duty_calculation. Business justification: LDP cost build-up for price master: price_master.landed_duty_paid_cost is derived from duty calculations. Apparel pricing teams reference the specific duty calculation that produced the LDP cost to su',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Price changes trigger revenue recognition and markdown accounting entries to specific GL accounts. Finance requires this link to automate GL posting of price changes and ensure proper revenue/markdown',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Price master records drive revenue recognition and transfer pricing journal entries in a specific ledger. Multi-GAAP apparel companies require ledger assignment on price master for parallel accounting',
    `price_book_id` BIGINT COMMENT 'Foreign key linking to merchandising.price_book. Business justification: Each price master record is governed by a price book that defines the pricing strategy, channel scope, and regional applicability. price_master has no price_book_id FK currently. Adding this FK normal',
    `region_id` BIGINT COMMENT 'Reference to the geographic region or market for which this price record applies. Supports regional pricing strategies across domestic and international markets.',
    `season_id` BIGINT COMMENT 'Reference to the merchandise season (e.g., Spring/Summer, Fall/Winter) associated with this price record. Supports seasonal buy plan and OTB (Open-to-Buy) budget alignment.',
    `sku_id` BIGINT COMMENT 'Reference to the specific SKU (Stock Keeping Unit) for which this price record applies. A SKU represents the most granular sellable unit (style + color + size). Links to the product/SKU master.',
    `style_id` BIGINT COMMENT 'Reference to the parent style record for which this pricing applies. A style may encompass multiple SKUs (colors and sizes). Enables style-level pricing analysis and rollup reporting.',
    `vendor_cost_quote_id` BIGINT COMMENT 'Foreign key linking to sourcing.vendor_cost_quote. Business justification: Retail pricing decisions reference vendor cost quotes to calculate IMU and validate margin targets. Essential for pricing strategy, ensuring retail prices achieve target margins based on actual source',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor. Business justification: Wholesale and FOB cost pricing are negotiated per vendor; merchandising requires vendor-specific cost tracking for margin analysis, vendor performance evaluation, and buy plan costing accuracy in appa',
    `approval_status` STRING COMMENT 'Workflow approval status of the price record within the Oracle Retail Price Management approval process. Prices must be approved before becoming active. Supports governance and audit trail for pricing decisions.. Valid values are `draft|submitted|approved|rejected`',
    `approved_by` STRING COMMENT 'Username or employee identifier of the merchandising manager or pricing analyst who approved this price record in Oracle Retail Price Management. Supports audit trail and pricing governance.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the price record was formally approved in the Oracle Retail Price Management workflow. Provides a precise audit trail for pricing governance and compliance reporting.',
    `aur` DECIMAL(18,2) COMMENT 'Average Unit Retail (AUR) — the average price at which a unit is actually sold after accounting for promotions, markdowns (MD), and clearance events. A key KPI in merchandise financial planning and STR (Sell-Through Rate) analysis. Managed in Anaplan merchandise planning.',
    `competitor_price` DECIMAL(18,2) COMMENT 'The observed or benchmarked competitor price for a comparable product at the time of pricing decision. Used to support competitive pricing analysis and market positioning strategy. Expressed in the currency defined by currency_code.',
    `cost_price` DECIMAL(18,2) COMMENT 'The landed cost price of the product including COGS (Cost of Goods Sold) components such as CMT (Cut Make Trim), materials, LDP (Landed Duty Paid) duties, and freight. Used as the denominator for IMU (Initial Markup) and MMU (Maintained Markup) calculations.',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 Alpha-3 country code identifying the specific country market for which this price record applies. Supports country-level pricing compliance, VAT/tax treatment, and international trade reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this price master record was first created in the system. Provides the audit trail creation anchor for the price record lifecycle.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which all monetary price fields (MSRP, wholesale price, cost price, AUR, markdown price) are expressed. Supports multi-currency pricing for international markets and regional price management.. Valid values are `^[A-Z]{3}$`',
    `effective_end_date` DATE COMMENT 'The date on which this price record expires and is no longer applicable for transactions. Nullable for open-ended pricing. Used to manage price validity windows, promotional end dates, and seasonal clearance cutoffs.',
    `effective_start_date` DATE COMMENT 'The date from which this price record becomes active and applicable for transactions. Used to manage price change calendars, promotional windows, and seasonal pricing transitions in Oracle Retail Price Management.',
    `fob_cost` DECIMAL(18,2) COMMENT 'FOB (Free on Board) cost representing the factory gate price paid to the supplier before freight and duty charges. Used in sourcing negotiations, BOM (Bill of Materials) costing, and supplier performance benchmarking.',
    `imu_percent` DECIMAL(18,2) COMMENT 'Initial Markup Percentage (IMU%) — the percentage markup applied at the time of first pricing, calculated as (MSRP - Cost Price) / MSRP × 100. A foundational metric in merchandise financial planning and OTB (Open-to-Buy) budget setting.',
    `landed_duty_paid_cost` DECIMAL(18,2) COMMENT 'Total LDP (Landed Duty Paid) cost including FOB (Free on Board) price, import duties, freight, insurance, and customs clearance charges. Used as the true cost basis for margin calculations and sourcing decisions.',
    `markdown_percent` DECIMAL(18,2) COMMENT 'The percentage reduction from MSRP applied during a markdown (MD) event, calculated as (MSRP - Markdown Price) / MSRP × 100. Used to track markdown depth, promotional cadence, and margin erosion in merchandise financial planning.',
    `markdown_price` DECIMAL(18,2) COMMENT 'The reduced selling price applied during a markdown (MD) event, clearance, or end-of-season promotion. Tracked separately from MSRP to enable markdown depth analysis and STR (Sell-Through Rate) optimization.',
    `min_advertised_price` DECIMAL(18,2) COMMENT 'The minimum price at which wholesale partners and retailers are contractually permitted to advertise this product. Enforced to protect brand equity and prevent price erosion in wholesale and marketplace channels.',
    `mmu_percent` DECIMAL(18,2) COMMENT 'Maintained Markup Percentage (MMU%) — the actual markup percentage realized after all markdowns (MD), promotions, and shrinkage adjustments. Reflects true profitability versus the initial pricing plan. Used in GMROI (Gross Margin Return on Investment) analysis.',
    `msrp` DECIMAL(18,2) COMMENT 'Manufacturers Suggested Retail Price (MSRP) — the recommended consumer-facing selling price set by the brand. Used as the baseline for IMU (Initial Markup) calculation, wholesale negotiations, and consumer price communication. Expressed in the currency defined by the currency_code field.',
    `price_change_reason` STRING COMMENT 'Business justification or reason code for the price change event (e.g., seasonal markdown, competitive response, cost increase, promotional event, clearance). Supports pricing audit trail and merchandise financial planning analysis.',
    `price_elasticity_index` DECIMAL(18,2) COMMENT 'A numeric index representing the price sensitivity of demand for this SKU/style, derived from historical sales and pricing data in Anaplan. Used to optimize markdown timing, promotional depth, and AUR (Average Unit Retail) planning.',
    `price_master_code` STRING COMMENT 'Externally-known business identifier for the price master record as assigned in Oracle Retail Price Management. Used for cross-system reference and EDI (Electronic Data Interchange) integration with wholesale partners and ERP systems.. Valid values are `^PM-[A-Z0-9]{6,20}$`',
    `price_status` STRING COMMENT 'Current lifecycle status of the price master record. Active records are currently in use; pending records are approved but not yet effective; expired records have passed their effective end date; superseded records have been replaced by a newer price version.. Valid values are `active|inactive|pending|expired|superseded`',
    `price_tier` STRING COMMENT 'Classification of the products price positioning within the brands pricing architecture. Drives assortment planning, channel allocation, and marketing strategy. [ENUM-REF-CANDIDATE: luxury|premium|mid_market|value|outlet|off_price — promote to reference product if tiers expand beyond 6]. Valid values are `luxury|premium|mid_market|value|outlet|off_price`',
    `price_type` STRING COMMENT 'Categorizes the nature of the price record — regular everyday price, promotional price, clearance/end-of-season price, wholesale price, cost price, or internal transfer price. Governs which price is applied in each transaction context.. Valid values are `regular|promotional|clearance|wholesale|cost|transfer`',
    `price_version` STRING COMMENT 'Sequential version number of the price record, incremented each time the price is updated or superseded. Enables price history tracking and point-in-time pricing reconstruction for audit and analytics purposes.',
    `price_zone_code` STRING COMMENT 'Code identifying the geographic or channel-based price zone to which this price record belongs. Price zones allow differentiated pricing across markets (e.g., US_EAST, EU_WEST, APAC) within Oracle Retail Price Management.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `sales_channel_type` STRING COMMENT 'The type of sales channel for which this price is applicable. DTC (Direct-to-Consumer) retail, DTC e-commerce, wholesale, outlet, marketplace, or franchise. Enables channel-specific pricing strategy and margin analysis.. Valid values are `dtc_retail|dtc_ecommerce|wholesale|outlet|marketplace|franchise`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this price record originated. ORM = Oracle Retail Merchandising, SAP_SD = SAP Sales & Distribution, SFCC = Salesforce Commerce Cloud, ANAPLAN = Anaplan Planning, MANUAL = manually entered. Supports data lineage and reconciliation.. Valid values are `ORM|SAP_SD|SFCC|ANAPLAN|MANUAL`',
    `tax_inclusive_flag` BOOLEAN COMMENT 'Indicates whether the MSRP and selling prices include applicable taxes (VAT, GST, sales tax). True = tax-inclusive pricing (common in EU/UK markets); False = tax-exclusive pricing (common in US markets). Governs POS and e-commerce price display.',
    `transfer_price` DECIMAL(18,2) COMMENT 'The internal price used for inter-company or inter-division product transfers (e.g., from distribution center to retail store, or between legal entities). Used in SAP S/4HANA FI/CO for intercompany accounting and IFRS transfer pricing compliance.',
    `upc_code` STRING COMMENT 'Universal Product Code (UPC) barcode identifier for the SKU. Used for POS (Point of Sale) scanning, RFID (Radio Frequency Identification) tagging, and retail shelf management. Conforms to GS1 UPC-A or EAN-13 standards.. Valid values are `^[0-9]{12,14}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this price master record was most recently modified. Used for incremental data pipeline processing, change data capture (CDC), and audit trail maintenance in the Databricks Silver Layer.',
    `vat_rate_percent` DECIMAL(18,2) COMMENT 'The applicable VAT (Value Added Tax) or GST rate percentage for this product in the specified country/region. Used for tax-inclusive price calculation, consumer receipt display, and regulatory tax reporting.',
    `wholesale_price` DECIMAL(18,2) COMMENT 'The price at which the product is sold to wholesale partners, department stores, and distribution accounts. Used in wholesale margin analysis, partner negotiations, and GMROI (Gross Margin Return on Investment) reporting.',
    CONSTRAINT pk_price_master PRIMARY KEY(`price_master_id`)
) COMMENT 'Master pricing record for each style/SKU capturing MSRP, AUR (Average Unit Retail), IMU (Initial Markup), wholesale price, and cost price across channels and regions. Tracks price tier classification (luxury, premium, value), currency, and effective date ranges. Managed in Oracle Retail Price Management module.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`promotion` (
    `promotion_id` BIGINT COMMENT 'Unique system-generated identifier for the promotion record. Primary key for the promotion data product in the merchandising domain.',
    `audience_segment_id` BIGINT COMMENT 'Foreign key linking to marketing.audience_segment. Business justification: Promotions are deployed to specific marketing audience segments (lapsed customers, loyalty tier, new acquires) distinct from CRM customer_segment_id. Marketing teams activate promotions via audience s',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Merchandising promotions (markdowns, discounts) are executed as part of marketing campaigns. This link tracks which campaign drives each pricing action, enabling integrated promotional planning and RO',
    `cluster_id` BIGINT COMMENT 'Foreign key linking to store.store_cluster. Business justification: Promotions in apparel are commonly scoped to store clusters (e.g., outlet cluster clearance events, flagship cluster VIP promotions). Cluster-level promotion targeting is a standard named process in a',
    `collection_id` BIGINT COMMENT 'Foreign key linking to product.collection. Business justification: Collection-level promotions are a standard apparel retail practice — end-of-season collection sales, new collection launch promotions. This FK enables promotion scoping by collection, collection markd',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Promotion costs (advertising, discounts, loyalty rewards) are charged to marketing/merchandising cost centers. Finance requires this link to allocate promotional expenses and track cost center budget ',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Promotions target customer segments beyond loyalty programs (student discounts, military offers, first-time buyer incentives). Segment-specific promotions drive acquisition and retention strategies wi',
    `event_id` BIGINT COMMENT 'Foreign key linking to marketing.event. Business justification: Promotional events (flash sales, trunk shows, end-of-season events) activate specific promotions. Merchandising teams track promotional lift per marketing event for markdown budget accountability. A f',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Promotions involve markdown budgets and discount costs posted to specific GL accounts (markdown expense, promotional allowance). Finance requires GL account assignment on promotions for promotional co',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Promotional markdown costs are accrued in a specific accounting ledger. Finance requires ledger assignment on promotions to post markdown expense accruals to the correct ledger for period-close and to',
    `loyalty_program_id` BIGINT COMMENT 'Reference to the loyalty program associated with loyalty-linked promotions. Null for non-loyalty promotion types. Links to CRM (Customer Relationship Management) loyalty program master data in Adobe Experience Platform or Salesforce.',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Promotions have department_id, class_id but no FK to merchandise_hierarchy master. Adding merchandise_hierarchy_id FK normalizes merchandise classification and removes redundant hierarchy attributes. ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Promotions impact margin by channel/brand, tracked via profit centers for ROI analysis. Financial reporting requires linking promotional lift and cost to profit centers to measure promotional effectiv',
    `promo_code_id` BIGINT COMMENT 'Foreign key linking to marketing.promo_code. Business justification: Marketing promo codes trigger merchandising promotions at checkout. This link connects the code distribution mechanism (marketing) to the discount rules and budget impact (merchandising). Essential fo',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Promotions are seasonal events (Spring Sale, Holiday Clearance); season_code exists but no FK to season master. Adding season_id FK normalizes season reference and removes redundant season_code. FK wi',
    `source_promotion_id` BIGINT COMMENT 'Original promotion identifier as recorded in the source operational system (e.g., Oracle Retail promotion number, SAP SD condition record number). Enables traceability and reconciliation between the Databricks Silver Layer and source systems of record.',
    `actual_lift_pct` DECIMAL(18,2) COMMENT 'Realized percentage increase in unit sales or revenue achieved by this promotion compared to baseline, captured post-promotion from SAP CAR POS data and Salesforce Commerce Cloud. Compared against planned_lift_pct for STR (Sell-Through Rate) analysis and future promotion planning.',
    `actual_revenue` DECIMAL(18,2) COMMENT 'Realized gross revenue generated during the promotion period, sourced from SAP CAR POS transactions and Salesforce Commerce Cloud order data. Compared against planned_revenue for post-promotion performance analysis and GMROI optimization.',
    `actual_units` STRING COMMENT 'Realized number of units sold during the promotion period, sourced from SAP CAR POS and Salesforce Commerce Cloud. Used in STR (Sell-Through Rate) analysis and post-promotion inventory reconciliation.',
    `approval_status` STRING COMMENT 'Workflow approval state of the promotion record within the merchandising governance process. Pending: awaiting review; Approved: authorized by merchandising director or finance; Rejected: not approved; Escalated: referred to senior leadership. Distinct from promotion_status which tracks operational lifecycle.. Valid values are `pending|approved|rejected|escalated`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the merchandising manager or director who authorized this promotion. Supports audit trail requirements for pricing governance and FTC compliance on promotional advertising claims.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the promotion was formally approved by the authorized merchandising stakeholder. Supports audit trail and compliance with FTC promotional advertising disclosure requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `channel_applicability` STRING COMMENT 'Sales channel(s) where the promotion is valid. Retail_store: physical POS via SAP CAR; ecommerce: digital storefront via Salesforce Commerce Cloud; wholesale: B2B distribution partners; dtc: Direct-to-Consumer (DTC) channels; all: applicable across all channels. Drives channel-specific promotional lift analysis.. Valid values are `all|retail_store|ecommerce|wholesale|dtc`',
    `coupon_code` STRING COMMENT 'Alphanumeric coupon or voucher code that customers enter at POS or e-commerce checkout to activate the promotion when coupon_required is True (e.g., SAVE20, LOYALTY10). Null when coupon_required is False.. Valid values are `^[A-Z0-9_-]{4,20}$`',
    `coupon_required` BOOLEAN COMMENT 'Indicates whether the customer must present or enter a coupon code to redeem the promotion. True = coupon code required at POS or e-commerce checkout; False = automatic/stackable promotion applied without customer action.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the promotion record was first created in the source system (Oracle Retail or SAP SD). Supports data lineage, audit trail, and GDPR/CCPA data governance requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code applicable to all monetary fields on this promotion record (e.g., USD, EUR, GBP). Supports multi-currency operations across international retail and wholesale channels.. Valid values are `^[A-Z]{3}$`',
    `discount_rate` DECIMAL(18,2) COMMENT 'Markdown (MD) percentage applied to the original MSRP or AUR (Average Unit Retail) for percentage-off promotion types. Expressed as a percentage (e.g., 25.00 = 25% off). Null for non-percentage promotion types such as fixed_price or bogo. Used in IMU/MMU (Initial Markup/Maintained Markup) impact analysis.',
    `end_date` DATE COMMENT 'Calendar date on which the promotion expires and is no longer applicable. Nullable for open-ended evergreen promotions. Used to calculate WOS (Weeks of Supply) impact and OTB (Open-to-Buy) planning in Anaplan.',
    `fixed_price_amount` DECIMAL(18,2) COMMENT 'Absolute promotional selling price applied to eligible items for fixed_price promotion types (e.g., $29.99). Null for percentage-off or BOGO mechanics. Represents the promotional AUR (Average Unit Retail) override in Oracle Retail Price Management.',
    `geographic_scope` STRING COMMENT 'Pipe-delimited list of ISO 3166-1 alpha-3 country codes where the promotion is valid (e.g., USA|CAN|GBR). Null = global applicability. Supports multi-market promotional planning and compliance with regional consumer protection regulations.. Valid values are `^[A-Z]{3}(|[A-Z]{3})*$`',
    `gmroi_impact` DECIMAL(18,2) COMMENT 'Estimated or realized GMROI (Gross Margin Return on Investment) impact of the promotion, calculated as gross margin dollars generated per dollar of inventory investment during the promotional period. A core KPI in apparel merchandising financial planning. Classified confidential as it reveals margin strategy.',
    `is_loyalty_exclusive` BOOLEAN COMMENT 'Indicates whether this promotion is exclusively available to loyalty program members. True = restricted to loyalty members only (tracked via Adobe Experience Platform or CRM); False = available to all customers. Supports CLTV (Customer Lifetime Value) and loyalty program ROI analysis.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when the promotion record was most recently modified in the source system. Tracks changes to promotion terms, dates, or discount mechanics for audit and data lineage purposes. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `markdown_budget` DECIMAL(18,2) COMMENT 'Allocated markdown (MD) budget for this promotion, representing the maximum planned reduction in gross margin approved by the merchandising team. Expressed in currency_code. Managed in Anaplan OTB (Open-to-Buy) financial planning. Classified confidential as it reflects internal pricing strategy.',
    `merchandise_scope` STRING COMMENT 'Level of the merchandise hierarchy to which the promotion applies. Determines eligible SKUs (Stock Keeping Units) in Oracle Retail: all_merchandise (storewide), department (e.g., Footwear), class (e.g., Running Shoes), subclass (e.g., Mens Running), sku (specific SKU), style (all colorways of a style). Drives assortment planning and allocation strategies.. Valid values are `all_merchandise|department|class|subclass|sku|style`',
    `minimum_purchase_amount` DECIMAL(18,2) COMMENT 'Minimum transaction value (in local currency) a customer must reach to qualify for the promotion. Used for threshold-based promotions (e.g., spend $100 get 20% off). Supports AOV (Average Order Value) uplift strategies in Salesforce Commerce Cloud and SAP CAR.',
    `minimum_quantity` STRING COMMENT 'Minimum number of units a customer must purchase to qualify for the promotion. Relevant for BOGO, bundle, and quantity-threshold promotions. Aligns with MOQ (Minimum Order Quantity) concepts in wholesale channel promotions.',
    `planned_lift_pct` DECIMAL(18,2) COMMENT 'Forecasted percentage increase in unit sales or revenue expected from this promotion compared to baseline, as planned in Anaplan merchandise financial planning. Used to set OTB (Open-to-Buy) budgets and evaluate GMROI (Gross Margin Return on Investment) impact pre-promotion.',
    `planned_revenue` DECIMAL(18,2) COMMENT 'Forecasted gross revenue expected to be generated during the promotion period, as modeled in Anaplan merchandise financial planning. Expressed in the currency defined by currency_code. Used for OTB budget setting and GMROI planning.',
    `planned_units` STRING COMMENT 'Forecasted number of units expected to be sold during the promotion period, as planned in Anaplan demand planning. Used to set inventory allocation targets and ATS (Available to Sell) thresholds in Manhattan Associates WMS.',
    `priority_rank` STRING COMMENT 'Numeric priority ranking used to resolve conflicts when multiple non-stackable promotions apply to the same transaction or item. Lower number = higher priority. Managed in Oracle Retail Price Management and SAP SD condition access sequences.',
    `promotion_code` STRING COMMENT 'Externally-known alphanumeric code used to identify and reference the promotion across Oracle Retail, SAP SD, and customer-facing channels (e.g., SUMMER25, BOGO-DENIM). Used in EDI transactions, POS systems, and e-commerce storefronts.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `promotion_description` STRING COMMENT 'Free-text business description of the promotions terms, conditions, and marketing narrative as communicated to customers and store associates (e.g., Get 25% off all womens outerwear this weekend only). Used in POS displays, e-commerce banners, and marketing collateral.',
    `promotion_name` STRING COMMENT 'Human-readable business name of the promotion as displayed in merchandising systems and marketing materials (e.g., Summer Clearance 2025, Buy One Get One Denim). Used in Oracle Retail and Anaplan merchandise financial planning.',
    `promotion_status` STRING COMMENT 'Current lifecycle state of the promotion record within Oracle Retail and SAP SD workflow. Draft: under construction; Approved: authorized by merchandising; Active: currently running; Paused: temporarily suspended; Expired: past end date; Cancelled: terminated before activation.. Valid values are `draft|approved|active|paused|expired|cancelled`',
    `promotion_type` STRING COMMENT 'Categorical classification of the promotions discount mechanic. Drives how the discount is calculated at POS and in e-commerce. Values: percentage_off (e.g., 20% off), fixed_price (e.g., $29.99), bogo (Buy One Get One), bundle (multi-item offer), loyalty (loyalty program linked reduction), clearance (end-of-season markdown). [ENUM-REF-CANDIDATE: percentage_off|fixed_price|bogo|bundle|loyalty|clearance|gift_with_purchase|threshold_discount — promote to reference product]. Valid values are `percentage_off|fixed_price|bogo|bundle|loyalty|clearance`',
    `sell_through_rate` DECIMAL(18,2) COMMENT 'Percentage of available promotional inventory sold during the promotion period (units sold / units available × 100). A key KPI in apparel merchandising for evaluating promotion effectiveness and informing future markdown (MD) and clearance strategies. Sourced post-promotion from Oracle Retail and SAP CAR.',
    `source_system` STRING COMMENT 'Operational system of record from which this promotion record originated. Oracle_retail: Oracle Retail Merchandising System; sap_sd: SAP S/4HANA Sales and Distribution; salesforce_cc: Salesforce Commerce Cloud; anaplan: Anaplan planning platform; manual: manually entered. Supports data lineage in the Databricks Silver Layer.. Valid values are `oracle_retail|sap_sd|salesforce_cc|anaplan|manual`',
    `stackable` BOOLEAN COMMENT 'Indicates whether this promotion can be combined with other active promotions on the same transaction. True = can stack with other promotions; False = exclusive promotion, cannot be combined. Critical for margin protection and MMU (Maintained Markup) management.',
    `start_date` DATE COMMENT 'Calendar date on which the promotion becomes effective and eligible for application at POS, e-commerce, and wholesale channels. Aligns with the T&A (Time and Action) calendar in Anaplan merchandise planning.',
    `usage_limit_per_customer` STRING COMMENT 'Maximum number of times a single customer can redeem this promotion. Null = unlimited per customer. Enforced at POS via SAP CAR and at e-commerce checkout via Salesforce Commerce Cloud to prevent abuse.',
    `usage_limit_total` STRING COMMENT 'Maximum total number of times this promotion can be redeemed across all customers and transactions. Null = unlimited redemptions. Used for limited-time flash sales and exclusive loyalty offers to control promotional liability.',
    CONSTRAINT pk_promotion PRIMARY KEY(`promotion_id`)
) COMMENT 'Master record for merchandise promotions including seasonal sales events, clearance promotions, bundle offers, and loyalty-linked price reductions. Captures promotion type, discount mechanics (percentage off, BOGO, fixed price), eligible merchandise scope, channel applicability, and planned versus actual promotional lift. Managed in Oracle Retail and SAP SD.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`merchandise_financial_plan` (
    `merchandise_financial_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the merchandise financial plan record in the Databricks Silver Layer. Primary key for this entity.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to merchandising.channel. Business justification: MFP has distribution_channel as a STRING attribute, which is a denormalized reference to the channel entity. MFPs are planned by channel (DTC, wholesale, e-commerce) in apparel financial planning. Add',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: MFPs in multi-entity apparel companies are scoped to a legal entity for statutory financial planning and consolidation. Finance requires company code assignment on MFPs to aggregate planned financials',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: MFP planned costs (COGS, markdowns, shrink) are allocated to cost centers for departmental accountability. Finance requires this link to track planned vs actual expenses by cost center for P&L varianc',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Financial plans forecast revenue by target customer segment. Segment penetration, wallet share, and growth projections drive OTB budgets and investment allocation across categories. Essential for segm',
    `division_id` BIGINT COMMENT 'Foreign key linking to merchandising.division. Business justification: Merchandise financial plans in apparel retail are organized by division (e.g., Mens, Womens, Kids). The division entity in this domain captures OTB budget amounts, target GMROIs, and markdown caden',
    `factory_capacity_id` BIGINT COMMENT 'Foreign key linking to production.factory_capacity. Business justification: Merchandise financial plans set planned receipt amounts and OTB that drive factory capacity booking decisions. Apparel planning teams reference MFP planned_receipts_amt when approving factory capacity',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: MFP planned net sales, COGS, and gross margin figures map to specific GL accounts for financial reporting. Finance uses this link to reconcile MFP planned P&L against GL actuals by merchandise hierarc',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Merchandise financial plans are reconciled against specific accounting ledgers during period-close. Finance teams align MFP planned net sales, COGS, and gross margin figures with ledger actuals for va',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Merchandise financial plans (MFP) are structured by merchandise hierarchy level (department, class) in Oracle Retail and Anaplan. MFP currently has class_code and department_code as STRING attributes ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: MFP planned revenue and margin are tracked via profit centers by channel/brand. Financial reporting requires linking merchandise financial plans to profit centers for segment P&L planning and performa',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Merchandise financial plans are seasonal planning entities; season_code and season_year exist but no FK to season master. Adding season_id FK normalizes season reference and removes redundant attribut',
    `approved_by` STRING COMMENT 'Name or employee identifier of the merchandising leader or finance officer who formally approved this merchandise financial plan.',
    `approved_date` DATE COMMENT 'The date on which the merchandise financial plan was formally approved by the merchandising leadership and finance team. Required for audit trail and OTB budget release.',
    `channel_inventory_allocation_pct` DECIMAL(18,2) COMMENT 'Percentage of total planned inventory allocated to this specific distribution channel (DTC retail, DTC e-commerce, wholesale, outlet). Drives channel-level receipt planning and allocation strategies in Oracle Retail.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this merchandise financial plan record was first created in the system. Used for audit trail and data lineage tracking in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which all monetary plan values are expressed (e.g., USD, EUR, GBP). Supports multi-currency planning for international wholesale and DTC channels.. Valid values are `^[A-Z]{3}$`',
    `fiscal_period` STRING COMMENT 'Fiscal quarter or period identifier within the fiscal year to which this plan applies (e.g., FY2025-Q1). Supports quarterly OTB budget reviews and financial reporting.. Valid values are `^FY[0-9]{4}-Q[1-4]$`',
    `fiscal_year` STRING COMMENT 'The companys fiscal year to which this merchandise financial plan belongs. May differ from calendar year depending on the companys fiscal calendar (e.g., fiscal year ending January 31).',
    `is_locked` BOOLEAN COMMENT 'Indicates whether this merchandise financial plan has been locked and frozen for execution. When True, no further edits are permitted and the plan serves as the official baseline for OTB budget management and performance tracking.',
    `plan_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this merchandise financial plan within Anaplan and Oracle Retail Merchandising System. Used for cross-system reconciliation and business reference.. Valid values are `^MFP-[A-Z0-9]{4,20}$`',
    `plan_end_date` DATE COMMENT 'The last date of the planning period covered by this merchandise financial plan. Marks the end of the seasons selling window and the EOM (End of Month) inventory target date.',
    `plan_name` STRING COMMENT 'Human-readable descriptive name of the merchandise financial plan, typically including season, year, department, and channel (e.g., FW2025 Womens Apparel DTC Retail Plan).',
    `plan_start_date` DATE COMMENT 'The first date of the planning period covered by this merchandise financial plan. Marks the beginning of the seasons selling window for OTB and inventory planning purposes.',
    `plan_status` STRING COMMENT 'Current lifecycle status of the merchandise financial plan. Draft indicates work-in-progress; submitted indicates pending approval; approved indicates finance/merchant sign-off; locked indicates frozen for execution; archived indicates superseded.. Valid values are `draft|submitted|approved|locked|archived`',
    `plan_type` STRING COMMENT 'Indicates whether the plan was generated using a top-down (executive-driven targets cascaded down), bottom-up (buyer/planner-driven builds rolled up), or reconciled (merged top-down and bottom-up) planning approach.. Valid values are `top_down|bottom_up|reconciled`',
    `plan_version` STRING COMMENT 'Version identifier of the merchandise financial plan (e.g., v1.0, v2.3). Supports iterative planning cycles where plans are revised across pre-season, in-season, and post-season phases.. Valid values are `^v[0-9]+.[0-9]+$`',
    `planned_aur` DECIMAL(18,2) COMMENT 'Planned AUR (Average Unit Retail) representing the expected average selling price per unit across the department/class/channel combination. Drives unit sales plan derivation from the net sales dollar plan.',
    `planned_bop_inventory_amt` DECIMAL(18,2) COMMENT 'Planned inventory value at retail at the beginning of the planning period. Used as the opening stock position for OTB calculations and inventory flow modeling.',
    `planned_cogs_amt` DECIMAL(18,2) COMMENT 'Planned COGS (Cost of Goods Sold) for the season, representing the total cost of merchandise expected to be sold. Used to derive planned gross margin and GMROI targets.',
    `planned_eop_inventory_amt` DECIMAL(18,2) COMMENT 'Planned inventory value at retail at the end of the planning period (EOM). Represents the target closing stock position and feeds into the next seasons BOP. Critical for OTB and WOS (Weeks of Supply) planning.',
    `planned_gmroi` DECIMAL(18,2) COMMENT 'Planned GMROI (Gross Margin Return on Investment) representing the gross margin dollars generated per dollar of average inventory investment. Core KPI for evaluating merchandise productivity and capital efficiency.',
    `planned_gross_margin_amt` DECIMAL(18,2) COMMENT 'Planned gross margin in absolute dollar terms (planned net sales minus planned COGS). Represents the financial contribution of the merchandise category before operating expenses.',
    `planned_gross_margin_pct` DECIMAL(18,2) COMMENT 'Planned gross margin expressed as a percentage of planned net sales (planned gross margin / planned net sales). Key KPI for merchandising performance and pricing strategy evaluation.',
    `planned_imu_pct` DECIMAL(18,2) COMMENT 'Planned IMU (Initial Markup) percentage representing the difference between the cost of merchandise and its original retail price, expressed as a percentage of retail. Establishes the pricing floor before markdowns.',
    `planned_inventory_turns` DECIMAL(18,2) COMMENT 'Planned number of times inventory is expected to sell through and be replenished during the season (COGS / average inventory at cost). Drives OTB budget and receipt flow planning.',
    `planned_markdown_amt` DECIMAL(18,2) COMMENT 'Total planned markdown (MD) dollars for the season representing the anticipated reduction from original retail price to drive sell-through. Directly impacts MMU and gross margin performance.',
    `planned_markdown_pct` DECIMAL(18,2) COMMENT 'Planned markdown as a percentage of planned net sales. Used to benchmark markdown aggressiveness across departments and channels and to set MMU expectations.',
    `planned_mmu_pct` DECIMAL(18,2) COMMENT 'Planned MMU (Maintained Markup) percentage representing the actual markup achieved after markdowns and promotions, expressed as a percentage of net sales. Reflects the realized pricing performance versus IMU.',
    `planned_msrp_avg` DECIMAL(18,2) COMMENT 'Planned average MSRP (Manufacturers Suggested Retail Price) across the SKUs in this department/class/channel plan. Establishes the retail price anchor for IMU calculation and consumer-facing pricing.',
    `planned_net_sales_amt` DECIMAL(18,2) COMMENT 'Total planned net sales revenue (gross sales minus returns and allowances) for the season, department, class, and channel combination. Core financial target in the merchandise financial plan. Expressed in the plans currency.',
    `planned_otb_amt` DECIMAL(18,2) COMMENT 'Planned OTB (Open-to-Buy) budget in dollars representing the amount of merchandise the buyer is authorized to purchase for the season. Calculated as planned EOP inventory + planned sales + planned markdowns - planned BOP inventory.',
    `planned_receipts_amt` DECIMAL(18,2) COMMENT 'Total planned merchandise receipts (inbound inventory) at retail value for the season. Represents the planned flow of new inventory into the channel to support the sales plan.',
    `planned_str_pct` DECIMAL(18,2) COMMENT 'Planned STR (Sell-Through Rate) expressed as a percentage of units sold versus units received. Target sell-through rate used to calibrate buy quantities, markdown timing, and end-of-season inventory positions.',
    `planned_units_sold` BIGINT COMMENT 'Total planned number of units expected to be sold during the season for the department/class/channel combination. Derived from planned net sales divided by planned AUR. Feeds into allocation and replenishment planning.',
    `planned_wos` DECIMAL(18,2) COMMENT 'Planned WOS (Weeks of Supply) representing the number of weeks the current inventory position is expected to last at the planned rate of sale. Used to identify over/under-stock risk and trigger replenishment actions.',
    `planning_horizon` STRING COMMENT 'Indicates the planning phase this plan represents: pre-season (initial buy plan before season starts), in-season (revised plan during active selling), or post-season (actuals reconciliation and hindsight).. Valid values are `pre_season|in_season|post_season`',
    `pricing_strategy` STRING COMMENT 'Planned pricing strategy for this channel and merchandise category: full_price (MSRP-driven), promotional (planned promotional events), value (everyday low price positioning), or outlet (clearance/off-price). Informs IMU and MMU targets.. Valid values are `full_price|promotional|value|outlet`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this merchandise financial plan record was last modified. Tracks iterative plan revisions across pre-season, in-season, and post-season planning cycles.',
    CONSTRAINT pk_merchandise_financial_plan PRIMARY KEY(`merchandise_financial_plan_id`)
) COMMENT 'Merchandise financial plan (MFP) capturing top-down and channel-level financial targets for a season by department, class, and distribution channel (DTC retail, DTC e-commerce, wholesale, outlet). Includes planned net sales, planned COGS, planned gross margin, planned GMROI, planned inventory turns, planned markdown dollars, channel-specific pricing strategy, and channel inventory allocation percentages. Serves as the financial planning backbone and GMROI target-setting mechanism for the merchandising organization. Managed in Anaplan.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`size_curve` (
    `size_curve_id` BIGINT COMMENT 'Unique surrogate identifier for the size curve profile record in the merchandising system. Primary key for the size_curve data product. Entity role: MASTER_RESOURCE — this is a planning reference resource defining expected unit sales distribution across size runs.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to merchandising.channel. Business justification: Size curves vary by channel in apparel — DTC stores may have different size distributions than wholesale accounts. size_curve has a channel STRING attribute that is a denormalized reference to the cha',
    `cluster_id` BIGINT COMMENT 'Foreign key linking to store.store_cluster. Business justification: Size curves in apparel are built per store cluster to reflect regional size demand patterns (e.g., larger sizes in certain regions). Planners assign size curves to clusters during buy planning. store_',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Segment-specific size curve derivation: size curves are built from sales data filtered by customer segment (e.g., petite vs. plus-size vs. athletic segments have distinct size distributions). Merchand',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Size curves are defined at the merchandise hierarchy class/subclass level — a size curve for Womens Tops differs from one for Mens Bottoms. size_curve currently has class_code, department_code, and ',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Size curves are often season-specific (seasonal adjustment factors, basis periods); season_code exists but no FK to season master. Adding season_id FK normalizes season reference and removes redundant',
    `size_scale_id` BIGINT COMMENT 'Foreign key linking to product.size_scale. Business justification: Size curves define percentage distributions across size ranges and must reference the actual size scale (XS-XXL, numeric, etc.) to be operationally meaningful. Allocation planning requires mapping cur',
    `sourcing_purchase_order_line_id` BIGINT COMMENT 'Foreign key linking to sourcing.sourcing_purchase_order_line. Business justification: Size curves determine the size-run quantities on sourcing PO lines. Buyers apply the size curve to set ordered_quantity per size_code on each PO line. This link enables size curve accuracy reporting b',
    `basis_period_end_date` DATE COMMENT 'End date of the historical sell-through data period used to derive this size curves distribution percentages. Together with basis_period_start_date, defines the historical window for statistical calibration of size ratios.',
    `basis_period_start_date` DATE COMMENT 'Start date of the historical sell-through data period used to derive this size curves distribution percentages. Defines the lookback window for statistical calibration. Typically covers 1-3 prior seasons of comparable selling history.',
    `confidence_level` STRING COMMENT 'Statistical confidence level of the size curve based on the volume and quality of historical sell-through data used in derivation. High confidence curves are used directly in buy plans; low confidence curves require planner override review. Drives curve applicability flags in Anaplan.. Valid values are `high|medium|low|insufficient_data`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this size curve record was first created in the system. Serves as the RECORD_AUDIT_CREATED field for this MASTER_RESOURCE entity. Stored in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX) per platform conventions.',
    `curve_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the size curve profile, used in Oracle Retail Merchandising System and Anaplan for cross-system reference. Serves as the BUSINESS_IDENTIFIER for this MASTER_RESOURCE entity.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `curve_derivation_method` STRING COMMENT 'Method used to derive the size distribution percentages for this curve. Historical STR uses actual sell-through data; planner_override reflects manual planner judgment; vendor_recommended uses supplier-provided size ratios; statistical_model uses algorithmic forecasting; blended combines multiple methods. Affects confidence level assignment.. Valid values are `historical_str|planner_override|vendor_recommended|statistical_model|blended`',
    `curve_name` STRING COMMENT 'Human-readable descriptive name for the size curve profile (e.g., Womens Fitted Tops Standard, Mens Denim 28-42 Bell Curve). Serves as the IDENTITY_LABEL for this MASTER_RESOURCE entity. Used in Oracle Retail and Anaplan planning interfaces.',
    `curve_type` STRING COMMENT 'Classification of the size curve profile indicating the fit and silhouette category that drives the distribution shape. Standard curves follow bell-curve distributions; fitted curves skew toward smaller sizes; oversized curves skew toward larger sizes. Serves as the CLASSIFICATION_OR_TYPE for this MASTER_RESOURCE entity. [ENUM-REF-CANDIDATE: standard|fitted|oversized|petite|plus|tall|slim|relaxed — promote to reference product]. Valid values are `standard|fitted|oversized|petite|plus|tall`',
    `effective_end_date` DATE COMMENT 'Date after which this size curve profile is no longer active for new planning runs. Null indicates an open-ended curve with no planned expiry. Used to manage curve versioning and seasonal transitions in Oracle Retail and Anaplan.',
    `effective_start_date` DATE COMMENT 'Date from which this size curve profile becomes effective for use in buy planning, allocation, and replenishment. Curves are versioned by effective date to support seasonal transitions and curve updates without disrupting in-flight planning cycles.',
    `is_default_for_class` BOOLEAN COMMENT 'Indicates whether this size curve is the default curve applied to new styles within the associated merchandise class when no style-specific curve exists. True = default fallback curve for the class. Used in Oracle Retail automated allocation and buy plan generation.',
    `is_replenishment_eligible` BOOLEAN COMMENT 'Indicates whether this size curve is approved for use in automated replenishment size pack calculations in Manhattan Associates WMS. True = curve can drive replenishment size breaks. False = curve is restricted to initial buy plan and allocation use only.',
    `last_reviewed_date` DATE COMMENT 'Date on which this size curve was last reviewed and validated by a merchandise planner. Curves not reviewed within a defined period (e.g., 2 seasons) are flagged for re-validation to ensure continued accuracy. Supports governance of curve quality.',
    `markdown_risk_index` DECIMAL(18,2) COMMENT 'Composite risk score (0.00-100.00) indicating the likelihood of size-related markdown exposure if this curve is applied to a buy plan. Derived from historical size fragmentation patterns and STR variance across sizes. Higher scores indicate greater markdown risk from size imbalance. Critical for GMROI optimization.',
    `notes` STRING COMMENT 'Free-text field for merchandise planner annotations regarding this size curve, including rationale for manual overrides, known anomalies in the historical basis data, or special instructions for application. Supports planning governance and knowledge transfer.',
    `numeric_size_distribution` STRING COMMENT 'Serialized representation of the size distribution percentages for numeric size runs (waist sizes 28-42 or equivalent), stored as a delimited string of size:percentage pairs (e.g., 28:5.0|30:12.0|32:22.0|34:25.0|36:18.0|38:12.0|40:4.0|42:2.0). Null for alpha or shoe size scale types. Used when the number of numeric sizes exceeds the available discrete percentage columns.',
    `pct_l` DECIMAL(18,2) COMMENT 'Expected percentage of total unit sales allocated to size L in the alpha size run. Expressed as a percentage (e.g., 25.00 = 25%). Null for numeric or shoe size scale types. Used in buy plan size ratio calculations and replenishment size pack optimization.',
    `pct_m` DECIMAL(18,2) COMMENT 'Expected percentage of total unit sales allocated to size M in the alpha size run. Expressed as a percentage (e.g., 28.00 = 28%). Typically the modal size in standard bell-curve distributions. Null for numeric or shoe size scale types.',
    `pct_s` DECIMAL(18,2) COMMENT 'Expected percentage of total unit sales allocated to size S in the alpha size run. Expressed as a percentage (e.g., 18.00 = 18%). Null for numeric or shoe size scale types. Used in buy plan size ratio calculations and allocation size breaks.',
    `pct_xl` DECIMAL(18,2) COMMENT 'Expected percentage of total unit sales allocated to size XL in the alpha size run. Expressed as a percentage (e.g., 14.00 = 14%). Null for numeric or shoe size scale types. Used in buy plan size ratio calculations and initial distribution planning.',
    `pct_xs` DECIMAL(18,2) COMMENT 'Expected percentage of total unit sales allocated to size XS in the alpha size run. Expressed as a percentage (e.g., 8.50 = 8.5%). Null for numeric or shoe size scale types. All size distribution percentages must sum to 100.00 for a valid curve. Serves as the principal MEASUREMENT_OR_VALUE for this MASTER_RESOURCE.',
    `pct_xxl` DECIMAL(18,2) COMMENT 'Expected percentage of total unit sales allocated to size XXL in the alpha size run. Expressed as a percentage (e.g., 6.50 = 6.5%). Null for numeric or shoe size scale types. Monitoring XXL distribution is critical for plus-size assortment planning and markdown minimization.',
    `region_code` STRING COMMENT 'Geographic region for which this size curve applies (e.g., NA, EMEA, APAC, LATAM). Size distributions vary significantly by region due to demographic differences. Used to apply region-specific size ratios in allocation and buy planning.. Valid values are `^[A-Z]{2,10}$`',
    `reviewed_by` STRING COMMENT 'Name or user identifier of the merchandise planner who last reviewed and validated this size curve. Provides accountability for curve quality and supports audit trail requirements for merchandise planning governance.',
    `sample_unit_count` STRING COMMENT 'Total number of units sold in the historical basis period used to derive this size curve. Higher sample counts yield higher statistical confidence. Used to validate confidence_level assignment — curves based on fewer than a threshold number of units are flagged as low confidence.',
    `seasonal_adjustment_factor` DECIMAL(18,2) COMMENT 'Multiplicative adjustment factor applied to the base size distribution percentages to account for seasonal demand shifts (e.g., 1.0500 = 5% upward adjustment). Captures known seasonal size preference changes such as outerwear seasons skewing larger. Applied in Anaplan seasonal buy plan calculations.',
    `shoe_size_distribution` STRING COMMENT 'Serialized representation of the size distribution percentages for shoe size runs (US sizes 5-14 or equivalent), stored as a delimited string of size:percentage pairs (e.g., 7:8.0|7.5:10.0|8:15.0|8.5:18.0|9:17.0|9.5:14.0|10:12.0|10.5:6.0). Null for alpha or numeric apparel size scale types.',
    `size_count` STRING COMMENT 'Total number of discrete sizes in the size run covered by this curve (e.g., 6 for XS-XXL alpha, 8 for 28-42 even numeric). Drives the number of size break columns populated in allocation and replenishment size pack calculations.',
    `size_curve_status` STRING COMMENT 'Current lifecycle status of the size curve profile. Active curves are used in live buy plans and allocation runs. Draft curves are under development. Archived curves are retained for historical analysis but excluded from new planning cycles. Serves as the LIFECYCLE_STATUS for this MASTER_RESOURCE entity.. Valid values are `active|inactive|draft|archived|under_review`',
    `size_range_max` STRING COMMENT 'The largest size in the size run covered by this curve (e.g., XXL, 42, 14). Combined with size_range_min to define the full size run span. Used to validate that buy plan size breaks fall within the defined range.',
    `size_range_min` STRING COMMENT 'The smallest size in the size run covered by this curve (e.g., XS, 28, 5). Combined with size_range_max to define the full size run span. Used to validate that buy plan size breaks fall within the defined range.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this size curve record originated. Supports data lineage tracking in the Databricks Silver Layer. Oracle Retail is the primary system of record; Anaplan is used for planning-layer curves; Centric PLM may provide initial vendor-recommended curves.. Valid values are `ORACLE_RETAIL|ANAPLAN|MANUAL|CENTRIC_PLM`',
    `str_basis_pct` DECIMAL(18,2) COMMENT 'The minimum Sell-Through Rate (STR) achieved in the historical basis period for the data to be considered statistically valid for curve derivation. Expressed as a percentage (e.g., 75.00 means 75% STR). Curves derived from low-STR periods may be flagged as low-confidence.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this size curve record was last modified. Tracks the most recent update to any attribute of the size curve profile. Used for incremental data pipeline processing in the Databricks Silver Layer and for audit trail purposes.',
    CONSTRAINT pk_size_curve PRIMARY KEY(`size_curve_id`)
) COMMENT 'Size curve profile master defining the expected unit sales distribution across size runs (alpha: XS/S/M/L/XL/XXL, numeric: 28-42, shoe: 5-14) for a style, merchandise class, or product category by channel, region, and store cluster. Captures curve type (standard, fitted, oversized), historical sell-through basis period, confidence level, and seasonal adjustment factors. Used to optimize buy plan size ratios, allocation size breaks, replenishment size packs, and initial distribution. Critical for minimizing size-related markdowns and stockouts in apparel where size fragmentation drives 15-20% of excess inventory. Managed in Oracle Retail and Anaplan.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`season` (
    `season_id` BIGINT COMMENT 'Unique surrogate identifier for the merchandise season record. Primary key for the season master reference table in the merchandising domain.',
    `channel_scope` STRING COMMENT 'The distribution channel scope for which this season is planned. All covers all channels; DTC covers direct-to-consumer retail and e-commerce; Wholesale covers wholesale and distribution partners. Drives channel-specific OTB allocation and assortment planning in Oracle Retail Merchandising System.. Valid values are `All|DTC|Wholesale|E-Commerce|Retail`',
    `clearance_end_date` DATE COMMENT 'The date by which all clearance selling for this season must be completed. After this date, remaining inventory is subject to return-to-vendor (RTV), off-price channel transfer, or write-off. Defines the final boundary of the seasons sell-through window.',
    `collection_theme` STRING COMMENT 'The creative or commercial theme name assigned to this seasons collection (e.g., Urban Explorer, Coastal Luxe). Defined during collection planning in Centric PLM and used to align product design, marketing campaigns, and visual merchandising narratives.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this season record was first created in the data platform. Supports audit trail, data lineage, and record lifecycle tracking in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which all monetary planning amounts for this season are denominated (e.g., USD, EUR, GBP). Ensures consistent financial reporting across multi-currency operations in SAP S/4HANA FI/CO and Anaplan.. Valid values are `^[A-Z]{3}$`',
    `end_date` DATE COMMENT 'The official last trading date of the merchandise season — the date on which the seasons assortment is retired from active selling. Defines the close of the OTB budget window and triggers end-of-season markdown cadence and clearance planning.',
    `first_delivery_date` DATE COMMENT 'The earliest scheduled date for merchandise receipts into the distribution center or stores for this season. Defines the opening of the delivery window and is a key milestone in the Time and Action (T&A) calendar for sourcing and procurement coordination.',
    `fiscal_half` STRING COMMENT 'The fiscal half-year period (H1 or H2) to which this season is aligned. Spring/Summer and Resort seasons typically fall in H1; Fall/Winter, Pre-Fall, and Holiday seasons in H2. Used for semi-annual merchandise financial planning (MFP) and OTB budget allocation in Anaplan.. Valid values are `H1|H2`',
    `fiscal_year` STRING COMMENT 'The fiscal year to which this season belongs for financial planning and reporting purposes (e.g., 2025). Aligns season-level OTB budgets and merchandise financial plans (MFP) to the corporate fiscal calendar in Anaplan and SAP S/4HANA FI/CO.',
    `gender_target` STRING COMMENT 'The primary gender target classification for this seasons collection, used to segment assortment planning, allocation strategies, and marketing campaigns. Aligns with product hierarchy classifications in Oracle Retail Merchandising System and Centric PLM.. Valid values are `Womens|Mens|Unisex|Kids|All`',
    `is_active` BOOLEAN COMMENT 'Indicates whether this season is currently active and available for use in planning, buying, and allocation transactions. Set to True when the season status is active; False for planning, closed, or archived seasons. Used to filter active seasons in Oracle Retail Merchandising System and Anaplan.',
    `is_nos` BOOLEAN COMMENT 'Indicates whether this season includes a Never Out of Stock (NOS) or carry-over program, where core styles are replenished continuously regardless of seasonal boundaries. NOS seasons require separate OTB budget allocation and replenishment planning in Oracle Retail Merchandising System.',
    `last_delivery_date` DATE COMMENT 'The latest permissible date for merchandise receipts for this season. Defines the close of the delivery window. Receipts after this date may be subject to late delivery penalties or cancellation per vendor agreements. Key milestone in the T&A calendar.',
    `markdown_cadence` STRING COMMENT 'The planned frequency of markdown (MD) events during the clearance phase of this season. Drives the markdown calendar in Oracle Retail Merchandising System Price Management and informs maintained markup (MMU) forecasting in Anaplan.. Valid values are `Weekly|Bi-Weekly|Monthly|Event-Driven`',
    `markdown_start_date` DATE COMMENT 'The date on which the first planned markdown (MD) event for this season begins. Initiates the end-of-season clearance cadence. Drives markdown (MD) planning in Oracle Retail Merchandising System Price Management and Anaplan merchandise financial planning.',
    `market_week_end_date` DATE COMMENT 'The end date of the industry market week associated with this season. Together with market_week_start_date, defines the window during which wholesale buyers finalize orders and assortment commitments.',
    `market_week_start_date` DATE COMMENT 'The start date of the industry market week (trade show / buying week) associated with this season, during which buyers review collections and place wholesale orders. Key date for collection planning and wholesale distribution calendars.',
    `mfp_version` STRING COMMENT 'The version identifier of the approved merchandise financial plan (MFP) associated with this season in Anaplan (e.g., v1.0-Initial, v2.1-Revised). Tracks plan revisions through the planning cycle and ensures alignment between OTB budgets and financial targets.',
    `num_planned_skus` STRING COMMENT 'The total number of distinct SKUs (Stock Keeping Units) planned for this season across all styles, colors, and sizes. Used to manage assortment breadth, warehouse capacity planning in Manhattan Associates WMS, and OTB unit buy planning.',
    `num_planned_styles` STRING COMMENT 'The total number of distinct styles (SKU parent-level products) planned for this seasons assortment. Set during collection planning in Centric PLM and used to manage line architecture, OTB depth-versus-breadth trade-offs, and assortment productivity analysis.',
    `order_deadline_date` DATE COMMENT 'The final date by which all purchase orders (POs) for this season must be submitted to suppliers to ensure on-time delivery within the seasons delivery window. Critical T&A calendar milestone managed in SAP S/4HANA MM and Centric PLM.',
    `otb_budget_amount` DECIMAL(18,2) COMMENT 'The total approved Open-to-Buy (OTB) budget in the companys reporting currency for this season. Represents the maximum planned merchandise spend authorized for buying activities. Set during merchandise financial planning (MFP) in Anaplan and tracked against actual PO commitments in Oracle Retail Merchandising System.',
    `planned_gross_margin_pct` DECIMAL(18,2) COMMENT 'The planned gross margin percentage for this season as set in the merchandise financial plan (MFP). Calculated as (planned sales minus planned cost of goods sold) divided by planned sales. Drives GMROI targets and IMU/MMU planning in Anaplan.',
    `planned_imu_pct` DECIMAL(18,2) COMMENT 'The planned initial markup (IMU) percentage for this season, representing the difference between the cost of goods and the initial retail price (MSRP) as a percentage of retail. Set during merchandise financial planning and used to guide pricing strategy in Oracle Retail Merchandising System Price Management.',
    `planned_sales_amount` DECIMAL(18,2) COMMENT 'The total planned net sales revenue in the companys reporting currency for this season as set during merchandise financial planning (MFP). Serves as the top-line revenue target against which actual sell-through rate (STR) and average unit retail (AUR) performance are measured.',
    `planned_str_pct` DECIMAL(18,2) COMMENT 'The planned sell-through rate (STR) percentage target for this season, representing the proportion of received inventory expected to be sold at full price before markdown. Used to benchmark actual in-season performance and trigger markdown cadence decisions.',
    `planning_start_date` DATE COMMENT 'The date on which internal merchandise planning activities formally begin for this season, including OTB budget setting, assortment planning, and buy plan development in Anaplan and Oracle Retail Merchandising System. Precedes the trading start date by several months.',
    `pre_production_start_date` DATE COMMENT 'The date on which pre-production (PP) activities commence for this season, including fabric and trim approvals, fit samples, and pre-production sample sign-off. Key milestone in the T&A calendar tracked in Centric PLM and Infor PLM.',
    `region_scope` STRING COMMENT 'The geographic region or market scope for which this season is defined (e.g., Global, North America, EMEA, APAC). Supports multi-regional merchandise planning where season start/end dates and delivery windows may vary by market. Used in Oracle Retail Merchandising System and Anaplan regional planning.',
    `season_description` STRING COMMENT 'Free-text narrative description of the season, capturing key strategic intent, collection positioning, target consumer profile, or planning notes. Used by merchandising and planning teams for context in Oracle Retail Merchandising System and Anaplan.',
    `season_name` STRING COMMENT 'Human-readable full name of the merchandise season (e.g., Spring/Summer 2025, Fall/Winter 2024, Holiday 2024, Resort 2025). Used in reporting, planning dashboards, and buyer-facing documents.',
    `season_status` STRING COMMENT 'Current lifecycle state of the merchandise season. planning indicates the season is in pre-production planning; active indicates the season is currently trading; closed indicates the season has ended trading; archived indicates the season is retained for historical reference only. Controls visibility in planning tools and reporting.. Valid values are `planning|active|closed|archived`',
    `season_type` STRING COMMENT 'Classification of the trading season by industry-standard merchandise calendar type. Drives collection planning, OTB budget cycles, and markdown cadence. [ENUM-REF-CANDIDATE: Spring/Summer|Fall/Winter|Resort|Pre-Fall|Holiday|Cruise — promote to reference product if additional season types are introduced]. Valid values are `Spring/Summer|Fall/Winter|Resort|Pre-Fall|Holiday|Cruise`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this season record was sourced (e.g., ORM = Oracle Retail Merchandising System, ANAPLAN = Anaplan, CENTRIC = Centric PLM). Supports data lineage tracking in the Databricks Silver Layer.. Valid values are `ORM|ANAPLAN|CENTRIC|INFOR_PLM`',
    `source_system_season_code` STRING COMMENT 'The native season identifier as recorded in the originating operational system of record (e.g., Oracle Retail Merchandising System season number, Anaplan season key). Enables traceability and reconciliation between the lakehouse Silver Layer and source systems.',
    `start_date` DATE COMMENT 'The official first trading date of the merchandise season — the date on which the seasons assortment becomes available for sale in retail stores and e-commerce channels. Serves as the temporal anchor for all season-level planning entities including assortment, OTB, allocation, and MFP.',
    `tna_calendar_code` STRING COMMENT 'Reference code linking this season to its associated Time and Action (T&A) calendar template in Centric PLM or Infor PLM. The T&A calendar defines all critical path milestones from design brief through to final delivery for the season.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this season record was last modified in the data platform. Used to detect changes, support incremental data loads, and maintain audit trail compliance in the Databricks Silver Layer.',
    `weeks_of_supply_target` DECIMAL(18,2) COMMENT 'The target number of weeks of supply (WOS) to be maintained during the peak trading period of this season. Used to calibrate inventory depth in buy plans and allocation strategies, ensuring sufficient stock without excess inventory build-up.',
    CONSTRAINT pk_season PRIMARY KEY(`season_id`)
) COMMENT 'Merchandise season master reference defining trading seasons (Spring/Summer, Fall/Winter, Resort, Pre-Fall, Holiday, Cruise) with start and end dates, delivery windows, market week dates, T&A calendar milestones, financial planning periods, and markdown cadence calendar. Every planning entity in the merchandising domain (assortment, collection, OTB, buy plan, allocation, MFP) references a season as its temporal anchor. Serves as the canonical time-boundary definition for merchandise planning cycles. Managed in Oracle Retail Merchandising System.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`price_change_event` (
    `price_change_event_id` BIGINT COMMENT 'Unique surrogate identifier for each price change event record in the merchandising system. Primary key for the price_change_event data product.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to merchandising.channel. Business justification: Price change events are channel-specific in apparel retail — a markdown applied in DTC stores may differ from wholesale pricing adjustments. price_change_event has channel as a STRING attribute. Addin',
    `cluster_id` BIGINT COMMENT 'Foreign key linking to store.store_cluster. Business justification: Price change events in apparel are frequently executed at store cluster level (e.g., markdown all outlet cluster stores simultaneously). Cluster-level markdown execution is a standard apparel pricing ',
    `collection_id` BIGINT COMMENT 'Foreign key linking to product.collection. Business justification: End-of-season collection clearance markdowns are a standard apparel practice — price change events are executed at collection level. This FK enables collection-level markdown tracking, collection clea',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Markdown decisions are tracked against cost center budgets for accountability. Finance requires this link to allocate markdown expenses to responsible cost centers and monitor markdown budget consumpt',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Targeted markdown events: price change events in fashion are often segment-targeted (e.g., loyalty Gold members receive early markdown access 48 hours before general public). This FK enables the prici',
    `event_id` BIGINT COMMENT 'Foreign key linking to marketing.event. Business justification: Markdowns and clearance price changes are coordinated with marketing events (end-of-season sales, brand events). Linking price_change_event to the triggering marketing event enables markdown cost attr',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Price changes post to specific GL accounts (markdown expense, inventory reserve, promotional allowance). Finance requires this link to automate GL posting of markdown events and ensure proper expense ',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Price change events (markdowns, clearance) generate GL postings that must be recorded in a specific accounting ledger. Finance requires ledger assignment on price change events to post markdown entrie',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Price changes (especially markdowns) are often timed to marketing campaigns. This link tracks which campaign drove the pricing decision, enabling analysis of campaign-driven markdown effectiveness and',
    `merchandise_hierarchy_id` BIGINT COMMENT 'Foreign key linking to merchandising.merchandise_hierarchy. Business justification: Price change events are applied at merchandise hierarchy levels (department, class, subclass) in retail pricing systems. price_change_event has class_code, department_code, and subclass_code as STRING',
    `price_master_id` BIGINT COMMENT 'Foreign key linking to merchandising.price_master. Business justification: Price change events modify prices; price_master is the authoritative source for pricing data. Adding price_master_id FK links transactional price changes to master pricing records and removes redundan',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Markdowns impact profit center margin performance. Financial reporting requires linking markdown events to profit centers to measure margin erosion by channel/brand and assess merchandising effectiven',
    `promotion_id` BIGINT COMMENT 'Reference to the promotional campaign or event that triggered this price change, if applicable. Links promotional price changes to the originating marketing or merchandising promotion.',
    `retail_store_id` BIGINT COMMENT 'Reference to the retail store, channel, or distribution location where this price change event is effective. Supports location-specific pricing strategies across DTC, wholesale, and e-commerce channels.',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Price change events (markdowns, promotions, clearance) are tied to merchandise seasons in apparel retail. price_change_event has season_code as a STRING attribute — a denormalized reference to the sea',
    `sku_id` BIGINT COMMENT 'Reference to the specific Stock Keeping Unit (SKU) to which this price change event applies. A SKU represents the most granular sellable unit (style-color-size combination).',
    `style_id` BIGINT COMMENT 'Reference to the parent style (product) to which this price change event applies. A price change may be applied at the style level and cascade to all associated SKUs.',
    `vendor_cost_quote_id` BIGINT COMMENT 'Foreign key linking to sourcing.vendor_cost_quote. Business justification: Markdown decisions consider original vendor costs from quotes to assess margin impact and determine vendor allowance eligibility. Critical for markdown planning, vendor negotiation for markdown suppor',
    `approval_date` DATE COMMENT 'The date on which the price change event was formally approved by the authorized merchandising manager or buyer. Required for governance compliance and audit trail in Oracle Retail Merchandising System.',
    `change_reason_code` STRING COMMENT 'Standardized reason code from Oracle Retail Merchandising System explaining the business rationale for the price change (e.g., SEASONAL_MD, COMPETITIVE_RESPONSE, CLEARANCE, PROMO, CORRECTION). Supports markdown (MD) analysis and GMROI reporting. [ENUM-REF-CANDIDATE: promote to reference product]',
    `change_reason_description` STRING COMMENT 'Free-text narrative description providing additional context for the price change event beyond the standardized reason code. Entered by the merchandising planner or buyer.',
    `change_type` STRING COMMENT 'Classification of the price change event by its business purpose. Permanent Markdown (MD) reduces the retail price indefinitely; Temporary Markdown is time-bound; Markup (MU) increases price; Clearance applies end-of-season liquidation pricing; Promotional applies campaign-driven pricing. [ENUM-REF-CANDIDATE: permanent_markdown|temporary_markdown|markup|clearance|promotional — promote to reference product]. Valid values are `permanent_markdown|temporary_markdown|markup|clearance|promotional`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this price change event record was first created in the system. Used for audit trail and data lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the price change amounts are denominated (e.g., USD, EUR, GBP). Supports multi-currency retail operations across international markets.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'The calendar date on which the new price becomes active and visible to customers across applicable channels. Used for scheduling future price changes in advance.',
    `end_date` DATE COMMENT 'The calendar date on which the price change expires and the price reverts to the prior or next scheduled price. Null for permanent price changes. Critical for temporary markdowns and promotional pricing.',
    `event_status` STRING COMMENT 'Current lifecycle state of the price change event within the Oracle Retail Merchandising System workflow. Drives whether the price change is visible and applied at POS and e-commerce channels.. Valid values are `pending|approved|active|expired|cancelled|rejected`',
    `event_timestamp` TIMESTAMP COMMENT 'The precise real-world date and time when the price change event was executed or became effective in the system of record. This is the principal business event time, distinct from audit timestamps.',
    `imu_percent` DECIMAL(18,2) COMMENT 'The Initial Markup (IMU) percentage for the affected SKU or style at the time of this price change event. Represents the original margin built into the retail price relative to cost. Used to assess markdown (MD) impact on maintained markup (MMU).',
    `is_clearance` BOOLEAN COMMENT 'Indicates whether this price change event designates the SKU or style as a clearance item. Once flagged as clearance, the item is typically excluded from future regular-price replenishment and tracked separately for end-of-season liquidation reporting.',
    `is_competitive_response` BOOLEAN COMMENT 'Indicates whether this price change event was triggered by a competitive pricing response to a market competitors price action. Supports competitive pricing analytics and brand positioning strategy.',
    `is_pos_applied` BOOLEAN COMMENT 'Indicates whether this price change event has been successfully transmitted and applied at the Point of Sale (POS) system via SAP Customer Activity Repository. Supports reconciliation between merchandising system and store operations.',
    `markdown_sequence_number` STRING COMMENT 'Sequential number indicating the ordinal position of this markdown (MD) event within the seasonal markdown cadence for the affected SKU or style (e.g., 1st markdown, 2nd markdown, 3rd markdown). Supports sell-through rate (STR) analysis and markdown optimization.',
    `mmu_percent` DECIMAL(18,2) COMMENT 'The Maintained Markup (MMU) percentage for the affected SKU or style after applying this price change event. Reflects the actual margin achieved post-markdown or post-markup. Key metric for GMROI optimization.',
    `new_retail_price` DECIMAL(18,2) COMMENT 'The updated retail selling price applied to the SKU or style as a result of this price change event. Represents the Average Unit Retail (AUR) post-change and is used in sell-through rate (STR) and GMROI analysis.',
    `original_retail_price` DECIMAL(18,2) COMMENT 'The retail selling price of the SKU or style immediately prior to this price change event. Serves as the baseline for calculating markdown (MD) depth, sell-through rate (STR) impact, and maintained markup (MMU).',
    `price_change_amount` DECIMAL(18,2) COMMENT 'The absolute monetary value of the price change (new_retail_price minus original_retail_price). A negative value indicates a markdown (MD); a positive value indicates a markup (MU). Used in merchandise financial planning and OTB impact analysis.',
    `price_change_level` STRING COMMENT 'Indicates the merchandise hierarchy level at which this price change event was initiated. A style-level change cascades to all associated SKUs; a SKU-level change applies only to the specific variant.. Valid values are `sku|style|department|class`',
    `price_change_number` STRING COMMENT 'Externally-known business identifier for the price change event as assigned by Oracle Retail Merchandising System or SAP S/4HANA SD module. Used for cross-system reconciliation and audit traceability.',
    `price_change_percent` DECIMAL(18,2) COMMENT 'The percentage change in retail price relative to the original retail price. Calculated as (price_change_amount / original_retail_price) * 100. Used for markdown (MD) depth reporting and sell-through rate (STR) analysis in Anaplan.',
    `pricing_zone_code` STRING COMMENT 'Code identifying the geographic or channel-based pricing zone to which this price change event applies. Pricing zones group locations with identical pricing strategies in Oracle Retail Merchandising System.',
    `source_system` STRING COMMENT 'Identifies the operational system of record that originated this price change event. Supports data lineage and cross-system reconciliation in the Databricks Silver Layer.. Valid values are `oracle_rms|sap_s4hana|anaplan|salesforce_cc|manual`',
    `str_at_change` DECIMAL(18,2) COMMENT 'The Sell-Through Rate (STR) for the affected SKU or style at the time of this price change event, expressed as a decimal (e.g., 0.65 = 65%). Provides context for the markdown decision and is used in post-event STR lift analysis.',
    `units_on_hand` STRING COMMENT 'The inventory quantity on hand for the affected SKU at the time of this price change event. Used to calculate the total markdown (MD) dollar exposure and weeks of supply (WOS) impact in merchandise financial planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this price change event record was last modified. Tracks amendments, corrections, or status updates to the price change event.',
    `wos_at_change` DECIMAL(18,2) COMMENT 'The Weeks of Supply (WOS) for the affected SKU at the time of this price change event, calculated as units on hand divided by average weekly sales rate. Used to assess inventory urgency and justify markdown (MD) depth decisions.',
    CONSTRAINT pk_price_change_event PRIMARY KEY(`price_change_event_id`)
) COMMENT 'Transactional record of any retail price modification event including permanent markdowns, temporary markdowns, markups, clearance pricing, and promotional price changes applied to a style or SKU';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`price_book` (
    `price_book_id` BIGINT COMMENT 'Primary key for price_book',
    `brand_id` BIGINT COMMENT 'Foreign key linking to product.brand. Business justification: Price books in multi-brand apparel retailers are brand-specific — luxury brands maintain separate price books from value brands. This FK enables brand-level pricing strategy management, brand price bo',
    `channel_id` BIGINT COMMENT 'Foreign key linking to merchandising.channel. Business justification: Price books in apparel retail are channel-specific — a DTC price book differs from a wholesale price book. price_book has channel as a STRING attribute. Adding channel_id FK normalizes this relationsh',
    `cluster_id` BIGINT COMMENT 'Foreign key linking to store.store_cluster. Business justification: Price books in apparel are assigned to store clusters — outlet clusters receive outlet price books, flagship clusters receive full-price books. Cluster-level price book assignment is a standard appare',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Price book segmentation: price_book.customer_segment is a plain text denormalization. Normalizing to a proper FK follows the established model pattern (assortment_plan, collection_plan, price_master, ',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Price books define pricing tiers and markup percentages that drive revenue GL postings. Finance uses price book GL account assignment for revenue recognition by price tier and channel, enabling automa',
    `loyalty_program_id` BIGINT COMMENT 'Foreign key linking to customer.loyalty_program. Business justification: Loyalty tier pricing: price books are directly tied to loyalty programs in fashion retail (e.g., Gold member price book, Platinum exclusive price book). This FK enables the pricing engine to automatic',
    `parent_version_price_book_id` BIGINT COMMENT 'Reference to the previous version of this price book, enabling version history tracking and audit trails.',
    `primary_base_price_book_id` BIGINT COMMENT 'Reference to parent or base price book when this price book is derived or inherits pricing rules from another.',
    `region_id` BIGINT COMMENT 'Foreign key linking to merchandising.region. Business justification: Price books are region-specific in apparel retail — pricing strategies differ by geographic region (e.g., North America vs. EMEA). price_book has region_code as a STRING attribute. Adding region_id FK',
    `season_id` BIGINT COMMENT 'Foreign key linking to merchandising.season. Business justification: Price books are seasonal pricing references. The price_book currently has season_code STRING attribute, which should be normalized to a FK to the season master table. This establishes the temporal con',
    `approved_by` STRING COMMENT 'Name or identifier of the merchandising manager or executive who approved this price book for use.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this price book was approved for operational use.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this price book record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all prices in this price book.',
    `effective_end_date` DATE COMMENT 'Date when the price book expires and pricing rules are no longer applicable. Nullable for open-ended price books.',
    `effective_start_date` DATE COMMENT 'Date when the price book becomes active and pricing rules become enforceable for merchandising operations.',
    `initial_markup_percentage` DECIMAL(18,2) COMMENT 'Initial markup percentage representing the difference between cost and original retail price for items in this price book.',
    `is_default` BOOLEAN COMMENT 'Boolean flag indicating whether this is the default price book for the organization or channel when no other price book applies.',
    `maintained_markup_percentage` DECIMAL(18,2) COMMENT 'Maintained markup percentage after markdowns, representing actual margin achieved for items in this price book.',
    `markdown_percentage` DECIMAL(18,2) COMMENT 'Default markdown percentage applied across items in this price book for promotional or clearance pricing.',
    `modified_by` STRING COMMENT 'Name or identifier of the user who last modified this price book record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Date and time when this price book record was last modified.',
    `notes` STRING COMMENT 'Free-text notes providing additional context, instructions, or business rationale for this price book.',
    `price_book_code` STRING COMMENT 'Externally-known unique business identifier for the price book used in merchandising systems and reporting.',
    `price_book_description` STRING COMMENT 'Detailed description of the price book purpose, scope, and application within merchandising operations.',
    `price_book_name` STRING COMMENT 'Human-readable name of the price book for identification and reporting purposes.',
    `price_book_status` STRING COMMENT 'Current lifecycle status of the price book indicating its operational state and availability for use.',
    `price_book_type` STRING COMMENT 'Classification of the price book indicating its primary merchandising purpose and pricing strategy application.',
    `pricing_strategy` STRING COMMENT 'Merchandising pricing strategy applied in this price book (MSRP: Manufacturer Suggested Retail Price).',
    `priority_rank` STRING COMMENT 'Numeric priority ranking used to resolve conflicts when multiple price books apply to the same item. Lower numbers indicate higher priority.',
    `requires_approval` BOOLEAN COMMENT 'Boolean flag indicating whether pricing changes in this price book require management approval before activation.',
    `rounding_rule` STRING COMMENT 'Rule applied for rounding calculated prices in this price book to achieve psychological pricing or operational simplicity.',
    `tax_inclusive` BOOLEAN COMMENT 'Boolean flag indicating whether prices in this price book include tax or are exclusive of tax.',
    `version_number` STRING COMMENT 'Sequential version number tracking revisions and updates to this price book over time.',
    `created_by` STRING COMMENT 'Name or identifier of the user who created this price book record.',
    CONSTRAINT pk_price_book PRIMARY KEY(`price_book_id`)
) COMMENT 'Master reference table for price_book. Referenced by price_book_id.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`division` (
    `division_id` BIGINT COMMENT 'Primary key for division',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Merchandising divisions map directly to cost centers for budget tracking and overhead allocation. Finance uses division-to-cost-center mapping for departmental P&L reporting, budget variance analysis,',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Division-segment alignment: division.target_customer_segment is a plain text denormalization. Normalizing to a proper FK follows the model pattern and enables merchandising planners to filter assortme',
    `parent_division_id` BIGINT COMMENT 'Reference to the parent division in a hierarchical division structure. Null for top-level divisions.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Merchandising divisions map to profit centers for divisional P&L reporting. Finance tracks revenue, gross margin, and GMROI by division via profit center assignment — a standard apparel finance report',
    `allocation_strategy` STRING COMMENT 'Primary allocation strategy used to distribute merchandise to stores for this division.',
    `buyer_name` STRING COMMENT 'Name of the primary buyer or merchandising manager responsible for this division.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this division record was first created in the system.',
    `division_code` STRING COMMENT 'Short alphanumeric code representing the division, used for reporting and system integration.',
    `division_description` STRING COMMENT 'Detailed description of the divisions scope, product categories, and business purpose.',
    `division_name` STRING COMMENT 'Full business name of the division (e.g., Mens Apparel, Womens Footwear, Accessories).',
    `division_status` STRING COMMENT 'Current lifecycle status of the division.',
    `division_type` STRING COMMENT 'Classification of the division by product category type.',
    `effective_end_date` DATE COMMENT 'Date when this division was discontinued or became inactive. Null for active divisions.',
    `effective_start_date` DATE COMMENT 'Date when this division became active in the merchandise hierarchy.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this division record was last updated.',
    `lead_time_weeks` STRING COMMENT 'Average lead time in weeks from order placement to merchandise receipt for this division.',
    `markdown_cadence` STRING COMMENT 'Typical frequency of markdown events for products in this division.',
    `merchandise_hierarchy_level` STRING COMMENT 'Numeric level of this division within the merchandise hierarchy (e.g., 1=Division, 2=Department, 3=Class).',
    `otb_budget_amount` DECIMAL(18,2) COMMENT 'Current open-to-buy budget amount allocated to this division for merchandise purchasing.',
    `otb_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the OTB budget amount.',
    `planner_name` STRING COMMENT 'Name of the primary merchandise planner responsible for assortment and allocation planning for this division.',
    `price_tier` STRING COMMENT 'Pricing tier classification for products within this division.',
    `private_label_percentage` DECIMAL(18,2) COMMENT 'Target percentage of private label merchandise within this divisions assortment.',
    `product_lifecycle_weeks` STRING COMMENT 'Average product lifecycle duration in weeks for merchandise in this division.',
    `replenishment_method` STRING COMMENT 'Method used for inventory replenishment for products in this division.',
    `seasonal_indicator` BOOLEAN COMMENT 'Indicates whether this division carries seasonal merchandise (True) or year-round merchandise (False).',
    `sort_order` STRING COMMENT 'Numeric value used to control the display order of divisions in reports and user interfaces.',
    `sustainability_rating` STRING COMMENT 'Sustainability rating for the division based on environmental and ethical sourcing practices.',
    `target_gmroi` DECIMAL(18,2) COMMENT 'Target GMROI for this division, calculated as gross margin dollars / average inventory cost.',
    `target_gross_margin_percentage` DECIMAL(18,2) COMMENT 'Target gross margin percentage for this division, used in merchandise financial planning.',
    `target_initial_markup_percentage` DECIMAL(18,2) COMMENT 'Target initial markup percentage for products in this division, calculated as (retail - cost) / retail * 100.',
    `target_maintained_markup_percentage` DECIMAL(18,2) COMMENT 'Target maintained markup percentage after markdowns for this division.',
    `target_sell_through_rate_percentage` DECIMAL(18,2) COMMENT 'Target sell-through rate percentage for this division, calculated as units sold / units received * 100.',
    `vendor_concentration_percentage` DECIMAL(18,2) COMMENT 'Percentage of division purchases concentrated with top vendors, used for risk assessment.',
    CONSTRAINT pk_division PRIMARY KEY(`division_id`)
) COMMENT 'Master reference table for division. Referenced by division_id.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`channel` (
    `channel_id` BIGINT COMMENT 'Primary key for channel',
    `segment_id` BIGINT COMMENT 'Foreign key linking to customer.segment. Business justification: Channel-segment targeting: channel.target_customer_segment is a plain text denormalization. A proper FK enables merchandising systems to automatically apply segment-appropriate assortments, promotions',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Sales channels (DTC, wholesale, e-commerce) map to specific GL accounts for channel-level revenue recognition. Finance uses channel-GL mapping for channel P&L reporting and automated revenue account d',
    `parent_channel_id` BIGINT COMMENT 'Reference to a parent channel if this channel is a sub-channel or variant within a hierarchical channel structure. Null for top-level channels.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Sales channels map to profit centers for channel-level P&L reporting. Finance tracks gross margin, AUR, and sell-through by channel via profit center assignment — essential for omnichannel profitabili',
    `region_id` BIGINT COMMENT 'Reference to the geographic region where this channel primarily operates.',
    `allocation_priority` STRING COMMENT 'Numeric priority ranking (1=highest) used in merchandise allocation strategies when distributing inventory across channels.',
    `assortment_strategy` STRING COMMENT 'Merchandising assortment strategy defining the breadth and depth of product selection offered through this channel.',
    `average_transaction_value` DECIMAL(18,2) COMMENT 'Historical average transaction value in the channels currency, used for financial planning and Gross Margin Return on Investment (GMROI) analysis.',
    `channel_category` STRING COMMENT 'High-level categorization of the channel by operational medium: physical (brick-and-mortar), digital (online), or omnichannel (integrated).',
    `channel_code` STRING COMMENT 'Short alphanumeric code representing the channel, used for reporting and system integration (e.g., WEB, RETAIL, WHSL).',
    `channel_description` STRING COMMENT 'Detailed business description of the channel, including its purpose, target customer segment, and operational characteristics.',
    `channel_name` STRING COMMENT 'Full business name of the sales and distribution channel (e.g., E-Commerce, Retail Stores, Wholesale Partners).',
    `channel_status` STRING COMMENT 'Current operational status of the channel in the merchandising system lifecycle.',
    `channel_type` STRING COMMENT 'Classification of the channel based on ownership and operational model (direct-owned, indirect-partner, hybrid, franchise, marketplace, outlet).',
    `commission_rate` DECIMAL(18,2) COMMENT 'Commission rate (as a decimal, e.g., 0.0500 for 5%) paid to channel partners or sales associates for transactions in this channel.',
    `contact_email` STRING COMMENT 'Primary email address for business inquiries and operational communication related to this channel.',
    `contact_phone` STRING COMMENT 'Primary phone number for business inquiries and operational communication related to this channel.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the primary country of operation for this channel.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this channel record was first created in the system.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code used for financial transactions in this channel.',
    `effective_end_date` DATE COMMENT 'Date when this channel ceased operations or was retired. Null for currently active channels.',
    `effective_start_date` DATE COMMENT 'Date when this channel became operational and available for transactions.',
    `fulfillment_method` STRING COMMENT 'Primary method used to fulfill customer orders in this channel: ship from store, ship from distribution center, in-store pickup, drop-ship, or mixed.',
    `inventory_visibility_flag` BOOLEAN COMMENT 'Indicates whether real-time inventory levels are visible to customers in this channel (True) or not (False).',
    `is_active` BOOLEAN COMMENT 'Indicates whether this channel record is currently active (True) or logically deleted/archived (False) in the system.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this channel record was last updated in the system.',
    `loyalty_program_eligible` BOOLEAN COMMENT 'Indicates whether purchases made through this channel are eligible for loyalty program points and rewards (True) or not (False).',
    `manager_name` STRING COMMENT 'Name of the business leader or manager responsible for this channels performance and strategy.',
    `markdown_policy` STRING COMMENT 'Markdown policy governing price reductions in this channel to optimize sell-through rate (STR) and inventory turnover.',
    `notes` STRING COMMENT 'Additional free-text notes, comments, or special instructions related to this channels operations or configuration.',
    `omnichannel_enabled` BOOLEAN COMMENT 'Indicates whether this channel is integrated into the omnichannel customer experience (True) or operates independently (False).',
    `operating_hours` STRING COMMENT 'Standard operating hours for this channel (e.g., 9:00 AM - 9:00 PM Mon-Sat, 24/7 for digital channels).',
    `payment_methods_accepted` STRING COMMENT 'Comma-separated list of payment methods accepted in this channel (e.g., credit card, debit card, digital wallet, cash, gift card).',
    `pricing_strategy` STRING COMMENT 'Primary pricing approach used in this channel: Manufacturers Suggested Retail Price (MSRP), promotional, clearance, dynamic, tiered, or wholesale pricing.',
    `return_policy_code` STRING COMMENT 'Code identifying the return and exchange policy applicable to purchases made through this channel.',
    `seasonal_flag` BOOLEAN COMMENT 'Indicates whether this channel operates seasonally (True) or year-round (False).',
    `target_initial_markup_percent` DECIMAL(18,2) COMMENT 'Target Initial Markup percentage for merchandise sold through this channel, used in Open-to-Buy (OTB) budget planning.',
    `target_maintained_markup_percent` DECIMAL(18,2) COMMENT 'Target Maintained Markup percentage after markdowns, used to measure pricing effectiveness and margin preservation.',
    `tax_jurisdiction_code` STRING COMMENT 'Code identifying the primary tax jurisdiction applicable to transactions in this channel for sales tax calculation.',
    `website_url` STRING COMMENT 'Primary website URL for digital channels or channel-specific landing pages.',
    CONSTRAINT pk_channel PRIMARY KEY(`channel_id`)
) COMMENT 'Master reference table for channel. Referenced by channel_id.';

CREATE OR REPLACE TABLE `apparel_fashion_ecm`.`merchandising`.`region` (
    `region_id` BIGINT COMMENT 'Primary key for region',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Regions in multi-entity apparel companies map to legal entities (company codes) for statutory reporting and tax jurisdiction compliance. Finance uses region-to-company-code mapping for legal entity co',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Merchandising regions map to cost centers for regional overhead allocation and budget tracking. Finance uses region-to-cost-center mapping for regional P&L reporting and budget variance analysis acros',
    `distribution_center_id` BIGINT COMMENT 'Reference to the primary distribution center serving this region for inventory allocation and fulfillment.',
    `parent_region_id` BIGINT COMMENT 'Reference to the parent region in a hierarchical region structure, enabling multi-level geographic or organizational rollups.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Merchandising regions map to profit centers for regional P&L reporting. Finance tracks revenue, gross margin, and OTB performance by region via profit center assignment — standard in apparel companies',
    `allocation_priority` STRING COMMENT 'Numeric priority ranking for inventory allocation decisions when supply is constrained (lower number = higher priority).',
    `aur_target_amount` DECIMAL(18,2) COMMENT 'Target average unit retail price for merchandise sold in this region, used for assortment planning and pricing strategy.',
    `climate_zone` STRING COMMENT 'Climate classification of the region used for seasonal assortment planning and collection timing.',
    `country_code` STRING COMMENT 'Three-letter ISO country code representing the primary country associated with this region.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this region record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO currency code representing the primary currency used for financial planning and reporting in this region.',
    `effective_end_date` DATE COMMENT 'Date when this region was discontinued or became inactive. Null indicates the region is currently active.',
    `effective_start_date` DATE COMMENT 'Date when this region became active and available for business operations and planning.',
    `gmroi_target` DECIMAL(18,2) COMMENT 'Target gross margin return on investment ratio for this region, measuring profitability of inventory investment.',
    `imu_target_percent` DECIMAL(18,2) COMMENT 'Target initial markup percentage for merchandise in this region, representing the difference between cost and initial retail price.',
    `is_ecommerce_enabled` BOOLEAN COMMENT 'Indicates whether e-commerce sales channels are active and operational in this region.',
    `is_wholesale_enabled` BOOLEAN COMMENT 'Indicates whether wholesale distribution partnerships are active in this region.',
    `language_code` STRING COMMENT 'Two-letter ISO language code representing the primary language used in this region for business communications.',
    `markdown_policy` STRING COMMENT 'Markdown policy governing price reduction strategies and timing for this region to optimize sell-through rate (STR) and gross margin return on investment (GMROI).',
    `market_size_category` STRING COMMENT 'Classification of the region based on market size and maturity for strategic planning and resource allocation.',
    `otb_budget_amount` DECIMAL(18,2) COMMENT 'Open-to-buy budget allocated to this region for merchandise purchasing, representing planned inventory investment.',
    `pricing_strategy` STRING COMMENT 'Primary pricing strategy applied in this region based on market positioning and competitive landscape.',
    `region_code` STRING COMMENT 'Short alphanumeric code representing the region, used for external identification and system integration.',
    `region_description` STRING COMMENT 'Detailed description of the region including its scope, coverage, and business purpose.',
    `region_level` STRING COMMENT 'Numeric level in the region hierarchy (e.g., 1=Global, 2=Continental, 3=Country, 4=State/Province, 5=District).',
    `region_name` STRING COMMENT 'Full business name of the region (e.g., North America, EMEA, Asia Pacific).',
    `region_status` STRING COMMENT 'Current lifecycle status of the region indicating whether it is actively used in business operations.',
    `region_type` STRING COMMENT 'Classification of the region based on its business purpose (geographic, sales, merchandising, distribution, operational, administrative).',
    `regulatory_compliance_notes` STRING COMMENT 'Free-text notes documenting region-specific regulatory requirements, trade restrictions, or compliance considerations.',
    `sales_target_amount` DECIMAL(18,2) COMMENT 'Annual sales target amount set for this region, used for performance measurement and planning.',
    `season_calendar_type` STRING COMMENT 'Seasonal calendar pattern used for merchandising planning in this region (e.g., northern hemisphere follows spring/summer/fall/winter).',
    `tax_jurisdiction_code` STRING COMMENT 'Code identifying the primary tax jurisdiction applicable to this region for sales tax and VAT calculations.',
    `time_zone` STRING COMMENT 'Standard time zone identifier for the region (e.g., America/New_York, Europe/London) used for scheduling and reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this region record was last modified in the system.',
    CONSTRAINT pk_region PRIMARY KEY(`region_id`)
) COMMENT 'Master reference table for region. Referenced by region_id.';

