ALTER TABLE `apparel_fashion_ecm`.`merchandising`.`assortment_plan` ADD CONSTRAINT `fk_merchandising_assortment_plan_merchandise_hierarchy_id` FOREIGN KEY (`merchandise_hierarchy_id`) REFERENCES `apparel_fashion_ecm`.`merchandising`.`merchandise_hierarchy`(`merchandise_hierarchy_id`);
ALTER TABLE `apparel_fashion_ecm`.`merchandising`.`assortment_plan` ADD CONSTRAINT `fk_merchandising_assortment_plan_otb_budget_id` FOREIGN KEY (`otb_budget_id`) REFERENCES `apparel_fashion_ecm`.`merchandising`.`otb_budget`(`otb_budget_id`);
ALTER TABLE `apparel_fashion_ecm`.`merchandising`.`assortment_plan` ADD CONSTRAINT `fk_merchandising_assortment_plan_season_id` FOREIGN KEY (`season_id`) REFERENCES `apparel_fashion_ecm`.`merchandising`.`season`(`season_id`);
